"use client";

import React, { useState, useMemo } from "react";
import { useWoznyStore, RowData } from "@/lib/store/useWoznyStore";
import { useAnalysisStore } from "@/lib/store/useAnalysisStore";
import { DataGrid } from "@/shared/DataGrid";
import { EmptyState } from "@/shared/EmptyState";
import { Wand2, Loader2, X, Download } from "lucide-react";
import { useWoznyLLM } from "@/lib/ai/useWoznyLLM";
import clsx from "clsx";
import { downloadCleanCsv } from "@/lib/export-utils";

export const AskWoznyView = () => {
  const rows = useWoznyStore((state) => state.rows);
  const columns = useWoznyStore((state) => state.columns);
  const fileName = useWoznyStore((state) => state.fileName);
  const setActiveTab = useWoznyStore((state) => state.setActiveTab);
  const setUserSelection = useWoznyStore((state) => state.setUserSelection);
  const sortConfig = useWoznyStore((state) => state.sortConfig);
  const toggleSort = useWoznyStore((state) => state.toggleSort);

  // Analysis for visibility
  const ignoredColumns = useAnalysisStore((state) => state.ignoredColumns);
  const showHiddenColumns = useWoznyStore((state) => state.showHiddenColumns);

  // Compute Visible Columns
  const visibleColumns = useMemo(() => {
    if (showHiddenColumns) return columns;
    return columns.filter((c) => !ignoredColumns.includes(c));
  }, [columns, ignoredColumns, showHiddenColumns]);

  // AI Hooks
  const {
    initialize,
    generateFilterCode,
    isReady,
    isLoading: isEngineLoading,
    progress,
  } = useWoznyLLM();
  const [aiQuery, setAiQuery] = useState("");
  const [aiFilterCode, setAiFilterCode] = useState<string | null>(null);
  const [isThinking, setIsThinking] = useState(false);

  // Filter Logic
  const filteredRows = useMemo(() => {
    if (!aiFilterCode) return rows;

    try {
      // 1. Extract Code Block (Smarter Extraction)
      // The AI often wraps code in markdown or prefixes text.
      let cleanCode = aiFilterCode.trim();

      // Regex to find code inside ``` ... ```
      const markdownMatch = cleanCode.match(
        /```(?:javascript|js)?\s*([\s\S]*?)\s*```/,
      );
      if (markdownMatch) {
        cleanCode = markdownMatch[1].trim();
      } else {
        // Fallback A: Look for the specific Arrow Function signature
        // The AI prompt demands "(row) =>", so we can reliably look for it.
        const arrowIndex = cleanCode.indexOf("(row) =>");
        if (arrowIndex !== -1) {
          cleanCode = cleanCode.substring(arrowIndex);
        }

        // Fallback B: Basic cleanup if no signature found (rare, effectively assumes pure code)
        cleanCode = cleanCode
          .replace(/```javascript/g, "")
          .replace(/```js/g, "")
          .replace(/```/g, "")
          .trim();
      }

      // 2. Handle generic variable declarations
      // Remove "const filter =", "let f =", "var x ="
      cleanCode = cleanCode.replace(/^(const|let|var)\s+\w+\s*=\s*/, "");

      // 3. Remove trailing semicolons
      cleanCode = cleanCode.trim();
      cleanCode = cleanCode.replace(/;$/, "");

      console.log("Raw AI Code:", aiFilterCode);
      console.log("Parsed Code:", cleanCode);

      // 4. Create Fuzzy Proxy Helper
      const createFuzzyRowProxy = (targetRow: RowData) => {
        return new Proxy(targetRow, {
          get: (target, prop) => {
            if (typeof prop !== "string") return Reflect.get(target, prop);

            // 1. Exact match
            if (prop in target) return target[prop];

            // 2. Case-insensitive match
            const exactKeys = Object.keys(target);
            const lowerProp = prop.toLowerCase();
            const key = exactKeys.find((k) => k.toLowerCase() === lowerProp);
            if (key) return target[key];

            // 3. Fallback (maybe Levenshtein later?)
            return undefined;
          },
        });
      };

      // 5. Create the filter function
      const expressionFn = new Function("row", `return (${cleanCode})(row)`);

      return rows.filter((row) => {
        try {
          // Wrap row in proxy to handle casing issues like "Account manager" vs "Account Manager"
          const proxyRow = createFuzzyRowProxy(row);
          return expressionFn(proxyRow);
        } catch (e) {
          return false;
        }
      });
    } catch (e) {
      console.error("Invalid Filter Code", e);
      // On error, return all rows (safe fallback) or maybe empty?
      // Returning all rows is safer to avoid empty screen panic.
      return rows;
    }
  }, [rows, aiFilterCode]);

  if (rows.length === 0) {
    return <EmptyState description="Upload a CSV file first." />;
  }

  // Handle AI Filter
  const handleAskWozny = async () => {
    if (!aiQuery.trim()) return;

    if (!isReady) {
      await initialize();
    }

    setIsThinking(true);
    setIsThinking(true);
    try {
      // Only feed visible columns to AI? Or give it all but tell it which are ignored?
      // For now, let's just give it visible columns to avoid confusion
      const code = await generateFilterCode(visibleColumns, aiQuery, rows);
      console.log("AI Code:", code);
      setAiFilterCode(code);
    } catch (e) {
      console.error("AI Error:", e);
    } finally {
      setIsThinking(false);
    }
  };

  const clearAiFilter = () => {
    setAiQuery("");
    setAiFilterCode(null);
  };

  const handleSendToWorkshop = () => {
    // Map current filtered row objects back to their global index
    // Note: rows[i] === row by reference
    const indices = filteredRows.map((row) => rows.indexOf(row));
    setUserSelection(indices);
    setActiveTab("workshop");
  };

  return (
    <div className="flex flex-col h-full animate-in fade-in duration-300 bg-neutral-50 dark:bg-neutral-900">
      {/* Toolbar / Search Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-neutral-200 dark:border-neutral-800 bg-white dark:bg-neutral-900 z-20">
        <div className="flex items-center gap-6">
          <div>
            <h2 className="text-lg font-bold flex items-center gap-2 text-neutral-900 dark:text-white">
              <Wand2 className="w-5 h-5 text-purple-600" />
              Ask Wozny
            </h2>
            <p className="text-xs text-neutral-500">
              Natural Language Filter Tool
            </p>
          </div>

          {/* AI Search Bar */}
          <div className="relative group">
            <div
              className={clsx(
                "flex items-center gap-2 bg-neutral-100 dark:bg-neutral-800 rounded-lg px-3 py-2 border border-transparent transition-all w-96 focus-within:w-[32rem] focus-within:border-purple-500 focus-within:bg-white dark:focus-within:bg-black shadow-sm",
                aiFilterCode &&
                  "border-purple-500 bg-purple-50 dark:bg-purple-900/20",
              )}
            >
              {isThinking || (isEngineLoading && !isReady) ? (
                <Loader2 className="w-5 h-5 animate-spin text-purple-600" />
              ) : (
                <Wand2
                  className={clsx(
                    "w-5 h-5",
                    aiFilterCode ? "text-purple-600" : "text-neutral-400",
                  )}
                />
              )}

              <input
                className="bg-transparent border-none outline-none text-sm w-full placeholder:text-neutral-400"
                placeholder={
                  !isReady
                    ? "Initializing AI..."
                    : "Example: Show me users from NY with missing emails..."
                }
                value={aiQuery}
                onChange={(e) => setAiQuery(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleAskWozny()}
                disabled={!isReady && isEngineLoading}
              />

              {aiFilterCode && (
                <button
                  onClick={clearAiFilter}
                  className="text-neutral-400 hover:text-neutral-900"
                >
                  <X className="w-4 h-4" />
                </button>
              )}
            </div>

            {!isReady && isEngineLoading && (
              <div className="absolute top-full left-0 mt-2 text-xs text-neutral-500 bg-white p-2 rounded shadow-lg border z-50 whitespace-nowrap">
                {progress}
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="text-sm text-neutral-500 font-mono">
            {filteredRows.length} / {rows.length} Rows
          </div>

          <button
            onClick={handleSendToWorkshop}
            disabled={filteredRows.length === 0}
            className="px-4 py-2 text-sm font-medium bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-all flex items-center gap-2 shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Wand2 className="w-4 h-4" />
            Send to Workshop
          </button>

          <button
            onClick={() => downloadCleanCsv(filteredRows, visibleColumns)}
            className="px-4 py-2 text-sm font-medium bg-neutral-900 dark:bg-white text-white dark:text-black rounded-lg hover:opacity-90 transition-all flex items-center gap-2"
          >
            <Download className="w-4 h-4" />
            Export
          </button>
        </div>
      </div>

      {/* Grid Container */}
      <div className="flex-1 overflow-hidden p-6 pb-0">
        {filteredRows.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-neutral-500 animate-in fade-in zoom-in-95 duration-200">
            <div className="bg-neutral-100 dark:bg-neutral-800 p-4 rounded-full mb-4">
              <Wand2 className="w-8 h-8 text-neutral-400" />
            </div>
            <h3 className="text-lg font-semibold text-neutral-900 dark:text-neutral-200">
              No results found
            </h3>
            <p className="text-sm max-w-xs text-center mt-2">
              We couldn't find any rows matching "{aiQuery}". Try rephrasing
              your search.
            </p>
            <button
              onClick={clearAiFilter}
              className="mt-6 text-sm font-medium text-purple-600 hover:text-purple-700 hover:underline"
            >
              Clear Filter
            </button>
          </div>
        ) : (
          <DataGrid
            data={filteredRows}
            columns={visibleColumns}
            className="shadow-sm border border-neutral-200 dark:border-neutral-800"
            sortConfig={sortConfig}
            onSort={toggleSort}
          />
        )}
      </div>
    </div>
  );
};

'use client';

import React from 'react';
import { useWoznyStore } from '@/lib/store/useWoznyStore';
import { useAnalysisStore } from '@/lib/store/useAnalysisStore';
import { DataGrid } from '@/shared/DataGrid';
import { Download, ArrowRight } from 'lucide-react';
import { EmptyState } from '@/shared/EmptyState';
import { downloadCleanCsv } from '@/lib/export-utils';

export const DiffView = () => {
    const rawRows = useWoznyStore((state) => state.rawRows);
    const rows = useWoznyStore((state) => state.rows);
    const columns = useWoznyStore((state) => state.columns);
    const fileName = useWoznyStore((state) => state.fileName);
    const setActiveTab = useWoznyStore((state) => state.setActiveTab);

    // Analysis Store (for ignored columns)
    const ignoredColumns = useAnalysisStore((state) => state.ignoredColumns);
    const toggleIgnoreColumn = useAnalysisStore((state) => state.toggleIgnoreColumn);
    const showHiddenColumns = useWoznyStore((state) => state.showHiddenColumns);

    // Filter Logic:
    // If showHiddenColumns is FALSE, we hide ignored columns from the View entirely.
    const visibleColumns = React.useMemo(() => {
        if (showHiddenColumns) return columns;
        return columns.filter(c => !ignoredColumns.includes(c));
    }, [columns, ignoredColumns, showHiddenColumns]);

    const sourceRef = React.useRef<HTMLDivElement>(null);
    const cleanRef = React.useRef<HTMLDivElement>(null);
    const isScrolling = React.useRef(false);

    // Synchronize Scroll
    React.useEffect(() => {
        const sourceCtx = sourceRef.current;
        const cleanCtx = cleanRef.current;

        if (!sourceCtx || !cleanCtx) return;

        const handleScroll = (e: Event) => {
            if (isScrolling.current) return;
            isScrolling.current = true;

            const target = e.target as HTMLDivElement;
            const other = target === sourceCtx ? cleanCtx : sourceCtx;

            other.scrollTop = target.scrollTop;
            other.scrollLeft = target.scrollLeft;

            // Reset lock after frame
            requestAnimationFrame(() => {
                isScrolling.current = false;
            });
        };

        sourceCtx.addEventListener('scroll', handleScroll);
        cleanCtx.addEventListener('scroll', handleScroll);

        return () => {
            sourceCtx.removeEventListener('scroll', handleScroll);
            cleanCtx.removeEventListener('scroll', handleScroll);
        };
    }, [rows]); // Re-attach if data changes (e.g. upload new file)

    if (rows.length === 0) {
        return <EmptyState description="Upload a CSV file to export results." />;
    }

    const handleExport = () => {
        downloadCleanCsv(rows, visibleColumns, fileName || 'clean_data');
    };

    return (
        <div className="h-full flex flex-col animate-in fade-in">
            {/* Header / Actions */}
            <div className="flex items-center justify-between px-6 py-4 bg-white dark:bg-neutral-900 border-b border-neutral-200 dark:border-neutral-800">
                <div>
                    <h2 className="text-xl font-bold text-neutral-900 dark:text-white">Review & Export</h2>
                    <p className="text-sm text-neutral-500 dark:text-neutral-400">Compare original vs cleaned data</p>
                </div>
                <button
                    onClick={handleExport}
                    className="flex items-center gap-2 px-6 py-3 bg-green-600 hover:bg-green-700 text-white font-bold rounded-lg shadow-lg shadow-green-500/20 transition-all hover:scale-105"
                >
                    <Download className="w-5 h-5" />
                    Download Cleaned CSV
                </button>
            </div>

            {/* Split View (Top/Bottom) */}
            <div className="flex-1 flex flex-col overflow-hidden">
                {/* Cleaned (Now Top) */}
                <div className="flex-1 flex flex-col border-b border-neutral-200 dark:border-neutral-800 min-h-0">
                    <div className="p-3 bg-blue-50 dark:bg-blue-900/20 text-center text-sm font-bold text-blue-800 dark:text-blue-200 uppercase tracking-widest border-b border-blue-200 dark:border-blue-800 shadow-sm z-10">
                        Cleaned Output
                    </div>
                    <div className="flex-1 overflow-hidden">
                        <DataGrid
                            ref={cleanRef}
                            data={rows}
                            columns={visibleColumns}
                            ignoredColumns={ignoredColumns}
                            onToggleIgnore={toggleIgnoreColumn}
                        />
                    </div>
                </div>

                {/* Arrow Divider (Points UP to Cleaned) */}
                <div className="h-8 bg-white dark:bg-neutral-950 flex items-center justify-center border-b border-neutral-200 dark:border-neutral-800 z-10">
                    <ArrowRight className="text-neutral-400 dark:text-neutral-700 -rotate-90" />
                </div>

                {/* Original (Now Bottom) */}
                <div className="flex-1 flex flex-col min-h-0">
                    <div className="p-3 bg-neutral-100 dark:bg-neutral-900/50 text-center text-sm font-bold text-neutral-800 dark:text-neutral-200 uppercase tracking-widest border-b border-neutral-200 dark:border-neutral-800 shadow-sm z-10">
                        Original Source
                    </div>
                    <div className="flex-1 overflow-hidden opacity-75">
                        <DataGrid
                            ref={sourceRef}
                            data={rawRows}
                            columns={visibleColumns}
                            ignoredColumns={ignoredColumns}
                            onToggleIgnore={toggleIgnoreColumn}
                        />
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { useWoznyStore } from '@/lib/store/useWoznyStore';
import { useAnalysisStore } from '@/lib/store/useAnalysisStore';
import { useMLWorker } from '@/lib/ai/useEmbeddingsWorker';
import { Sparkles, Play, Check, Loader2 } from 'lucide-react';

export const SmartAnalysisView = () => {
    const columns = useWoznyStore((state) => state.columns);
    const rows = useWoznyStore((state) => state.rows);
    const addColumn = useWoznyStore((state) => state.addColumn);
    const { groupTexts, status, progress } = useMLWorker();

    const [analyzingColumn, setAnalyzingColumn] = useState<string | null>(null);
    const ignoredColumns = useAnalysisStore((state) => state.ignoredColumns);

    // Filter for "interesting" text columns (has more than 5 unique values, logic could be improved)
    const textColumns = columns.filter(col => {
        // Skip ignored columns
        if (ignoredColumns.includes(col)) return false;

        // Just a simple heuristic: is it a string?
        // CSV is always string. Maybe skip 'ID' columns?
        return true;
    });

    const handleAnalyze = async (col: string) => {
        setAnalyzingColumn(col);
        const texts = rows.map(r => r[col] || '');

        try {
            // Run K-Means (k=5 default for now)
            const clusterIds = await groupTexts(texts, 5);

            // Map IDs to Group Names (e.g., "Group 1", "Group 2")
            // In a real app, we'd find the centermost text and name it "Like 'Google'"
            // clusterIds is Int32Array, convert to standard array
            const groupValues = Array.from(clusterIds).map(id => `Cluster ${id + 1}`);

            // Add to store
            addColumn(`${col} Group`, groupValues);

        } catch (e) {
            console.error(e);
            alert("Analysis failed. See console.");
        } finally {
            setAnalyzingColumn(null);
        }
    };

    return (
        <div className="h-full overflow-y-auto p-6">
            <div className="mb-6">
                <h2 className="text-xl font-bold flex items-center gap-2 mb-2">
                    <Sparkles className="w-5 h-5 text-purple-500" />
                    Smart Analysis
                </h2>
                <p className="text-neutral-500 text-sm">
                    Use machine learning to discover patterns, group similar items, and clean your data automatically.
                </p>
            </div>

            <div className="space-y-4">
                {textColumns.map(col => (
                    <div key={col} className="p-4 border border-neutral-200 dark:border-neutral-800 rounded-lg bg-white dark:bg-neutral-900 flex items-center justify-between">
                        <div>
                            <h3 className="font-semibold">{col}</h3>
                            <p className="text-xs text-neutral-400">
                                {rows.length} entries
                            </p>
                        </div>

                        {analyzingColumn === col ? (
                            <div className="flex items-center gap-3">
                                <div className="text-xs text-purple-500 font-medium">
                                    {status === 'working' ? `Analyzing ${progress}%` : 'Finalizing...'}
                                </div>
                                <Loader2 className="w-5 h-5 animate-spin text-purple-500" />
                            </div>
                        ) : (
                            <button
                                onClick={() => handleAnalyze(col)}
                                disabled={status === 'working'}
                                className="flex items-center gap-2 px-3 py-1.5 bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-300 rounded hover:bg-purple-100 dark:hover:bg-purple-900/40 transition-colors text-sm font-medium disabled:opacity-50"
                            >
                                <Play className="w-4 h-4" />
                                Group by Similarity
                            </button>
                        )}
                    </div>
                ))}
            </div>
        </div>
    );
};

import React, { useEffect, useState } from "react";
import { useWoznyStore } from "@/lib/store/useWoznyStore";
import {
  Activity,
  Database,
  Trash2,
  HardDrive,
  Cpu,
  AlertTriangle,
  CheckCircle2,
  ShieldCheck,
  WifiOff,
  FileCheck,
  FlaskConical,
} from "lucide-react";
import { ConfirmDialog } from "@/components/ui/ConfirmDialog";
import { initDB, exec, query } from "@/lib/db/db";

export const StatusView = () => {
  const storage = useWoznyStore((state) => state.storageUsage);
  const checkStorage = useWoznyStore((state) => state.checkStorage);
  const [clearing, setClearing] = useState<string | null>(null);

  // OPFS smoke test state
  type SmokeStatus = "idle" | "loading" | "ok" | "error";
  const [smokeStatus, setSmokeStatus] = useState<SmokeStatus>("idle");
  const [smokeRows, setSmokeRows] = useState<Record<string, unknown>[]>([]);
  const [smokeError, setSmokeError] = useState<string | null>(null);
  const [dbTables, setDbTables] = useState<string[]>([]);
  const [ignoredDbColumns, setIgnoredDbColumns] = useState<string[]>([]);
  const [sessionInfo, setSessionInfo] = useState<{
    count: number;
    active: { file_name: string; created_at: string } | null;
    cleanRowCount: number;
  } | null>(null);
  const [sessionHistory, setSessionHistory] = useState<
    {
      id: number;
      file_name: string;
      created_at: string;
      is_active: number;
      row_count: number;
    }[]
  >([]);
  const [clearing3a, setClearing3a] = useState(false);

  const [modelStatus, setModelStatus] = useState<{
    llama: boolean;
    embedding: boolean;
  }>({ llama: false, embedding: false });

  const checkModelCache = async () => {
    try {
      const keys = await caches.keys();
      let llamaFound = false;
      let embeddingFound = false;

      for (const key of keys) {
        // Check for WebLLM/MLC (Llama)
        if (key.includes("webllm") || key.includes("mlc")) {
          const cache = await caches.open(key);
          const requests = await cache.keys();
          if (requests.length > 0) llamaFound = true;
        }

        // Check for Transformers (Embedding)
        // Looks for the specific model folder or cache signature
        if (key.includes("transformers-cache")) {
          const cache = await caches.open(key);
          const requests = await cache.keys();
          // Basic check: if the cache has content, we assume the model is there
          // (Transformers.js usually puts everything in one cache)
          if (requests.length > 0) embeddingFound = true;
        }
      }
      setModelStatus({ llama: llamaFound, embedding: embeddingFound });
    } catch (e) {
      console.error("Cache check failed", e);
      setModelStatus({ llama: false, embedding: false });
    }
  };

  useEffect(() => {
    checkStorage();
    checkModelCache();
    const interval = setInterval(() => {
      checkStorage();
      checkModelCache();
    }, 5000); // Poll every 5s
    return () => clearInterval(interval);
  }, []);

  const runSmokeTest = async () => {
    setSmokeStatus("loading");
    setSmokeError(null);
    try {
      await initDB();
      await exec(`CREATE TABLE IF NOT EXISTS _smoke (
                id  INTEGER PRIMARY KEY AUTOINCREMENT,
                ts  TEXT NOT NULL
            )`);
      await exec(`INSERT INTO _smoke (ts) VALUES (?)`, [
        new Date().toISOString(),
      ]);
      const rows = await query(`SELECT * FROM _smoke ORDER BY id`);
      setSmokeRows(rows);

      // Phase 2b: query the list of tables to verify schema was created
      const tableRows = await query<{ name: string }>(
        `SELECT name FROM sqlite_master WHERE type='table' ORDER BY name`,
      );
      setDbTables(tableRows.map((r) => r.name));

      // Phase 3b: query ignored_columns table to verify ignored-column write path
      try {
        const ignoredRows = await query<{ column_name: string }>(
          `SELECT ic.column_name
           FROM ignored_columns ic
           JOIN sessions s ON ic.session_id = s.id
           WHERE s.is_active = 1
           ORDER BY ic.column_name`,
        );
        setIgnoredDbColumns(ignoredRows.map((r) => String(r.column_name)));
      } catch {
        setIgnoredDbColumns([]);
      }

      // Phase 3a: query session and row data to verify the write path
      try {
        const sessionCountRows = await query<{ count: number }>(
          `SELECT COUNT(*) AS count FROM sessions`,
        );
        const activeSessionRows = await query<{
          file_name: string;
          created_at: string;
        }>(
          `SELECT file_name, created_at FROM sessions WHERE is_active = 1 LIMIT 1`,
        );
        const cleanRowCountRows = await query<{ count: number }>(
          `SELECT COUNT(*) AS count FROM dataset_rows WHERE row_type = 'clean'`,
        );
        setSessionInfo({
          count: sessionCountRows[0]?.count ?? 0,
          active: activeSessionRows[0] ?? null,
          cleanRowCount: cleanRowCountRows[0]?.count ?? 0,
        });
      } catch {
        // sessions table may be empty on first load before any upload — not an error
        setSessionInfo({ count: 0, active: null, cleanRowCount: 0 });
      }

      // Phase 3c: query full session history to confirm old sessions are preserved
      try {
        const historyRows = await query<{
          id: number;
          file_name: string;
          created_at: string;
          is_active: number;
          row_count: number;
        }>(
          `SELECT s.id, s.file_name, s.created_at, s.is_active,
                  (SELECT COUNT(*) FROM dataset_rows dr
                   WHERE dr.session_id = s.id AND dr.row_type = 'clean') AS row_count
           FROM sessions s
           ORDER BY s.id DESC
           LIMIT 10`,
        );
        setSessionHistory(historyRows);
      } catch {
        setSessionHistory([]);
      }

      setSmokeStatus("ok");
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      setSmokeError(msg);
      setSmokeStatus("error");
    }
  };

  useEffect(() => {
    runSmokeTest();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const formatBytes = (bytes: number) => {
    if (bytes === 0) return "0 B";
    const k = 1024;
    const sizes = ["B", "KB", "MB", "GB", "TB"];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
  };

  const getHealthColor = (percent: number) => {
    if (percent > 80) return "bg-red-500 text-red-600";
    if (percent > 60) return "bg-yellow-500 text-yellow-600";
    return "bg-green-500 text-green-600";
  };

  const [dialogState, setDialogState] = useState<{
    type: "model" | "app" | null;
    isOpen: boolean;
  }>({ type: null, isOpen: false });

  // Open confirmation dialogs
  const requestClearModel = () =>
    setDialogState({ type: "model", isOpen: true });
  const requestResetApp = () => setDialogState({ type: "app", isOpen: true });
  const closeDialog = () => setDialogState({ type: null, isOpen: false });

  const proceedWithAction = async () => {
    if (dialogState.type === "model") {
      await clearModelCache();
    } else if (dialogState.type === "app") {
      await clearAppCache();
    }
    closeDialog(); // Close immediately after implementation starts/setup, or let the function handle it if we want loading state in dialog
    // Current implementation has loading state on buttons, so we can close dialog and let page loading state take over.
  };

  const clearModelCache = async () => {
    // Removed native confirm
    setClearing("model");
    try {
      const keys = await caches.keys();
      let cleared = false;
      for (const key of keys) {
        if (
          key.includes("transformer") ||
          key.includes("webllm") ||
          key.includes("mlc")
        ) {
          await caches.delete(key);
          cleared = true;
        }
      }

      await checkStorage();
      await checkModelCache();
    } catch (e) {
      alert("Failed to clear cache: " + e);
    } finally {
      setClearing(null);
    }
  };

  const clearAppCache = async () => {
    setClearing("app");
    try {
      // 1. Close the db worker so it releases its OPFS file handles before
      //    we attempt to delete the directory they're holding.
      const { closeDB } = await import("@/lib/db/db");
      closeDB();

      // 2. Give the worker a moment to fully terminate.
      await new Promise<void>((resolve) => setTimeout(resolve, 250));

      // 3. Delete only the Wozny OPFS directory — leaves model caches
      //    (WebLLM IndexedDB + Transformers.js Cache API) completely intact.
      try {
        const root = await navigator.storage.getDirectory();
        await root.removeEntry("wozny-db", { recursive: true });
      } catch (e: unknown) {
        const err = e as DOMException;
        // NotFoundError just means the directory was never created — fine.
        if (err?.name !== "NotFoundError") throw e;
      }

      // 4. Clear web storage (no Wozny data lives here, but clear for hygiene).
      localStorage.clear();
      sessionStorage.clear();

      // 5. Reload into a clean state.
      window.location.reload();
    } catch (e) {
      alert("Failed to reset app data: " + e);
      setClearing(null);
    }
  };

  return (
    <div className="h-full overflow-y-auto bg-neutral-50 dark:bg-neutral-900 p-8">
      <ConfirmDialog
        isOpen={dialogState.isOpen && dialogState.type === "model"}
        onClose={closeDialog}
        onConfirm={proceedWithAction}
        title="Delete AI Models?"
        description="This will permanently delete all downloaded Llama-3.2 and Embedding model weights. You will need to download them again to use AI features."
        confirmLabel="Delete Models"
        variant="danger"
      />

      <ConfirmDialog
        isOpen={dialogState.isOpen && dialogState.type === "app"}
        onClose={closeDialog}
        onConfirm={proceedWithAction}
        title="Factory Reset Application?"
        description="This permanently deletes your imported CSVs, cleaning history, and all session data from this device. AI model caches (Llama, Embeddings) are NOT affected — use 'Clear Model Caches' above to remove those separately. This action cannot be undone."
        confirmLabel="Factory Reset"
        variant="danger"
      />

      <div className="max-w-6xl mx-auto space-y-8">
        {/* Top Row: Header & Storage Split */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
          <header>
            <h1 className="text-3xl font-bold text-neutral-900 dark:text-white flex items-center gap-3">
              <Activity className="w-8 h-8 text-blue-500" />
              System Status & Compliance
            </h1>
            <p className="text-neutral-500 mt-2">
              Monitor local resource usage, manage data retention, and verify
              privacy status.
            </p>
          </header>

          {/* Storage Health Card */}
          <div className="bg-white dark:bg-black border border-neutral-200 dark:border-neutral-800 rounded-xl p-6 shadow-sm h-full flex flex-col justify-center">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded-lg">
                  <HardDrive className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                </div>
                <div>
                  <h3 className="font-bold text-lg">Storage Quota</h3>
                  <p className="text-sm text-neutral-500">
                    Browser-allocated space for this origin
                  </p>
                </div>
              </div>
              <div className="text-right">
                <span className="text-2xl font-mono font-bold">
                  {storage ? formatBytes(storage.used) : "..."}
                </span>
                <span className="text-neutral-400 text-sm ml-2">
                  / {storage ? formatBytes(storage.quota) : "..."}
                </span>
              </div>
            </div>

            {storage && (
              <div className="w-full h-4 bg-neutral-100 dark:bg-neutral-800 rounded-full overflow-hidden mb-2">
                <div
                  className={`h-full transition-all duration-500 ${getHealthColor(storage.percent).split(" ")[0]}`}
                  style={{ width: `${Math.max(2, storage.percent)}%` }}
                />
              </div>
            )}
            <div className="flex justify-between text-xs font-medium text-neutral-500 uppercase tracking-wide">
              <span>Low Usage</span>
              <span>Critical Limit</span>
            </div>
          </div>
        </div>

        {/* OPFS Smoke Test Card */}
        <div className="bg-white dark:bg-black border border-neutral-200 dark:border-neutral-800 rounded-xl p-6 shadow-sm">
          <div className="flex items-center gap-3 mb-4">
            <div className="p-2 bg-indigo-50 dark:bg-indigo-900/20 rounded-lg">
              <FlaskConical className="w-5 h-5 text-indigo-600 dark:text-indigo-400" />
            </div>
            <div>
              <h3 className="font-bold text-neutral-900 dark:text-white">
                OPFS Persistence — Phase 1 Smoke Test
              </h3>
              <p className="text-xs text-neutral-500 mt-0.5">
                Verifies that the wa-sqlite OPFS worker can write and re-read
                rows across page refreshes.
              </p>
            </div>
            <div className="ml-auto">
              {smokeStatus === "loading" && (
                <span className="text-xs font-medium text-indigo-500 animate-pulse">
                  Running…
                </span>
              )}
              {smokeStatus === "ok" && (
                <span className="flex items-center gap-1 text-xs font-bold text-green-600 dark:text-green-400 bg-green-50 dark:bg-green-900/20 px-2 py-1 rounded">
                  <CheckCircle2 className="w-3 h-3" /> OPFS OK
                </span>
              )}
              {smokeStatus === "error" && (
                <span className="flex items-center gap-1 text-xs font-bold text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 px-2 py-1 rounded">
                  <AlertTriangle className="w-3 h-3" /> Failed
                </span>
              )}
            </div>
          </div>

          {smokeStatus === "ok" && smokeRows.length > 0 && (
            <div className="space-y-3">
              <div className="flex items-center gap-4 text-sm">
                <span className="text-neutral-500">First load:</span>
                <span className="font-mono text-neutral-900 dark:text-white">
                  {String(smokeRows[0].ts)}
                </span>
              </div>
              <div className="flex items-center gap-4 text-sm">
                <span className="text-neutral-500">Row count:</span>
                <span className="font-mono font-bold text-neutral-900 dark:text-white">
                  {smokeRows.length}
                </span>
                {smokeRows.length > 1 ? (
                  <span className="text-xs text-green-600 dark:text-green-400 font-medium">
                    ✓ Persisted across {smokeRows.length - 1} refresh
                    {smokeRows.length - 1 !== 1 ? "es" : ""}
                  </span>
                ) : (
                  <span className="text-xs text-neutral-400">
                    (refresh the page to confirm persistence)
                  </span>
                )}
              </div>

              {dbTables.length > 0 && (
                <div className="pt-2 border-t border-neutral-100 dark:border-neutral-800">
                  <p className="text-xs font-semibold text-neutral-500 uppercase tracking-wide mb-2">
                    Phase 2b — Schema Tables ({dbTables.length})
                  </p>
                  <div className="flex flex-wrap gap-1.5">
                    {dbTables.map((name) => (
                      <span
                        key={name}
                        className="font-mono text-xs px-2 py-0.5 rounded bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300 border border-indigo-100 dark:border-indigo-800"
                      >
                        {name}
                      </span>
                    ))}
                  </div>
                </div>
              )}

              {/* Phase 3b: ignored columns DB contents */}
              <div className="pt-2 border-t border-neutral-100 dark:border-neutral-800">
                <p className="text-xs font-semibold text-neutral-500 uppercase tracking-wide mb-2">
                  Phase 3b — Ignored Columns in DB ({ignoredDbColumns.length})
                </p>
                {ignoredDbColumns.length === 0 ? (
                  <span className="text-xs text-neutral-400 italic">
                    none — ignore a column then re-run smoke test
                  </span>
                ) : (
                  <div className="flex flex-wrap gap-1.5">
                    {ignoredDbColumns.map((name) => (
                      <span
                        key={name}
                        className="font-mono text-xs px-2 py-0.5 rounded bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-300 border border-amber-200 dark:border-amber-800"
                      >
                        {name}
                      </span>
                    ))}
                  </div>
                )}
              </div>

              {/* Phase 3c: session history */}
              {sessionHistory.length > 0 && (
                <div className="pt-2 border-t border-neutral-100 dark:border-neutral-800">
                  <p className="text-xs font-semibold text-neutral-500 uppercase tracking-wide mb-2">
                    Phase 3c — Session History ({sessionHistory.length})
                  </p>
                  <div className="space-y-1.5">
                    {sessionHistory.map((s) => (
                      <div
                        key={s.id}
                        className={`flex items-center justify-between text-xs rounded px-2 py-1.5 ${
                          s.is_active
                            ? "bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800"
                            : "bg-neutral-50 dark:bg-neutral-800/50 border border-neutral-100 dark:border-neutral-700"
                        }`}
                      >
                        <div className="flex items-center gap-2 min-w-0">
                          <span
                            className={`w-1.5 h-1.5 rounded-full shrink-0 ${s.is_active ? "bg-green-500" : "bg-neutral-300 dark:bg-neutral-600"}`}
                          />
                          <span className="font-mono truncate text-neutral-800 dark:text-neutral-200">
                            {s.file_name ?? "Untitled"}
                          </span>
                        </div>
                        <div className="flex items-center gap-3 shrink-0 ml-2 text-neutral-500">
                          <span>
                            {Number(s.row_count).toLocaleString()} rows
                          </span>
                          <span
                            className={`font-medium ${s.is_active ? "text-green-600 dark:text-green-400" : "text-neutral-400"}`}
                          >
                            {s.is_active ? "Active" : "Archived"}
                          </span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {sessionInfo !== null && (
                <div className="pt-2 border-t border-neutral-100 dark:border-neutral-800">
                  <p className="text-xs font-semibold text-neutral-500 uppercase tracking-wide mb-2">
                    Phase 3a — Write Path
                  </p>
                  <div className="space-y-1 text-sm">
                    <div className="flex items-center gap-4">
                      <span className="text-neutral-500 w-28 shrink-0">
                        Sessions total:
                      </span>
                      <span className="font-mono font-bold text-neutral-900 dark:text-white">
                        {sessionInfo.count}
                      </span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-neutral-500 w-28 shrink-0">
                        Active file:
                      </span>
                      <span className="font-mono text-neutral-900 dark:text-white truncate">
                        {sessionInfo.active?.file_name ?? (
                          <span className="text-neutral-400 italic">
                            none — upload a CSV to verify
                          </span>
                        )}
                      </span>
                    </div>
                    {sessionInfo.active && (
                      <div className="flex items-center gap-4">
                        <span className="text-neutral-500 w-28 shrink-0">
                          Clean rows:
                        </span>
                        <span className="font-mono font-bold text-neutral-900 dark:text-white">
                          {sessionInfo.cleanRowCount.toLocaleString()}
                        </span>
                        {sessionInfo.cleanRowCount > 0 && (
                          <span className="text-xs text-green-600 dark:text-green-400 font-medium">
                            ✓ Write path confirmed
                          </span>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {smokeStatus === "error" && smokeError && (
            <p className="text-sm text-red-600 dark:text-red-400 font-mono bg-red-50 dark:bg-red-900/10 rounded p-3">
              {smokeError}
            </p>
          )}

          <div className="mt-4 flex items-center gap-3">
            <button
              onClick={runSmokeTest}
              disabled={smokeStatus === "loading" || clearing3a}
              className="text-xs font-medium px-3 py-1.5 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300 border border-indigo-200 dark:border-indigo-800 rounded-lg hover:bg-indigo-100 dark:hover:bg-indigo-900/30 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              {smokeStatus === "loading" ? "Running…" : "Re-run Smoke Test"}
            </button>
            <button
              onClick={async () => {
                setClearing3a(true);
                try {
                  await exec(`DELETE FROM ignored_columns`);
                  await exec(`DELETE FROM analysis_issues`);
                  await exec(`DELETE FROM dataset_rows`);
                  await exec(`DELETE FROM dataset_meta`);
                  await exec(`DELETE FROM sessions`);
                  setSessionInfo({ count: 0, active: null, cleanRowCount: 0 });
                } catch (e) {
                  console.error("[debug] Clear Wozny data failed:", e);
                } finally {
                  setClearing3a(false);
                }
              }}
              disabled={smokeStatus === "loading" || clearing3a}
              className="text-xs font-medium px-3 py-1.5 bg-red-50 dark:bg-red-900/10 text-red-600 dark:text-red-400 border border-red-200 dark:border-red-900/30 rounded-lg hover:bg-red-100 dark:hover:bg-red-900/20 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              title="Test utility — clears all Wozny session data from OPFS. Does not affect model caches."
            >
              {clearing3a ? "Clearing…" : "Clear Wozny Data"}
            </button>
          </div>
        </div>

        {/* Main 2-Column Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Left Column: Data Management (Danger Zone) */}
          <div className="space-y-6">
            <div className="flex items-center gap-2 mb-2 px-2">
              <Trash2 className="w-4 h-4 text-neutral-400" />
              <h2 className="text-sm font-bold text-neutral-500 uppercase tracking-wider">
                Data Retention Management
              </h2>
            </div>

