// --- SINGLETON WORKER STATE ---
let globalWorker: Worker | null = null;
let activeConsumers = 0;
let retentionTimeout: NodeJS.Timeout | null = null;

const WORKER_RETENTION_MS = 1000; // Keep worker alive for 1s during navigation

export const useMLWorker = () => {
    const [status, setStatus] = useState<MLResponse['status']>('ready');
    const [progress, setProgress] = useState(0);
    const [error, setError] = useState<string | null>(null);
    const [device, setDevice] = useState<'cpu' | 'webgpu' | 'wasm' | 'unknown'>('unknown');
    const [workerId, setWorkerId] = useState(0); // Used to force re-render/re-init

    useEffect(() => {
        // 1. Cancel destruction if we're remounting/navigating quickly
        if (retentionTimeout) {
            clearTimeout(retentionTimeout);
            retentionTimeout = null;
        }

        // 2. Initialize Worker if needed
        if (!globalWorker) {
            globalWorker = new Worker(
                new URL('./embeddings.worker.ts', import.meta.url),
                { type: 'module' }
            );
            console.log("[ML Worker] Initialized Singleton");
        }

        activeConsumers++;

        // 3. Status Listener (Shared / Global Updates)
        // This listener handles generic "error" or "ready" states that might affect everyone
        // NOTE: Request-specific progress is better handled in the promise, to avoid noise
        const globalHandler = (event: MessageEvent<MLResponse>) => {
            const { status, error, data } = event.data;
            if (status === 'error' && !event.data.requestId) {
                // Global worker error (not specific to a request)
                setError(error || 'Unknown global worker error');
                setStatus('error');
            }
            // Listen for device info
            if (status === 'ready' && (event.data as any).device) {
                setDevice((event.data as any).device);
            }
        };

        globalWorker.addEventListener('message', globalHandler);

        // 4. Cleanup
        return () => {
            if (globalWorker) {
                globalWorker.removeEventListener('message', globalHandler);
            }

            activeConsumers--;

            if (activeConsumers === 0) {
                // Start grace period before termination
                retentionTimeout = setTimeout(() => {
                    if (activeConsumers === 0 && globalWorker) {
                        console.log("[ML Worker] Terminating Zombie");
                        globalWorker.terminate();
                        globalWorker = null;
                        setDevice('unknown');
                    }
                }, WORKER_RETENTION_MS);
            }
        };
    }, [workerId]); // Re-run when workerId changes (forced reset)

    const resetWorker = useCallback(() => {
        if (globalWorker) {
            globalWorker.terminate();
            globalWorker = null;
        }
        activeConsumers = 0; // Reset count
        if (retentionTimeout) clearTimeout(retentionTimeout);
        setWorkerId(prev => prev + 1); // Force effect to re-run
        setError(null);
        setStatus('ready');
        setDevice('unknown');
    }, []);

    const generateEmbeddings = useCallback((texts: string[]): Promise<Float32Array[]> => {
        return new Promise((resolve, reject) => {
            if (!globalWorker) {
                reject('Worker not initialized');
                return;
            }

            const requestId = Math.random().toString(36).substring(7);

            const handler = (event: MessageEvent<MLResponse>) => {
                const { status, data, task, error, requestId: resId, progress } = event.data;

                // IGNORE messages not for this request
                if (resId !== requestId) return;

                if (status === 'complete' && task === 'feature-extraction') {
                    globalWorker?.removeEventListener('message', handler);
                    // Type guard: ensure data is Float32Array[]
                    if (Array.isArray(data) && (data.length === 0 || data[0] instanceof Float32Array)) {
                        resolve(data as Float32Array[]);
                    } else {
                        reject('Invalid data type received from worker');
                    }
                    setStatus('ready');
                } else if (status === 'error') {
                    globalWorker?.removeEventListener('message', handler);
                    reject(error);
                    setError(error || 'Calculation failed');
                    setStatus('error');
                } else if (status === 'working') {
                    setStatus('working');
                    // Only update progress for this specific request
                    if (progress !== undefined) setProgress(progress);
                }
            };

            globalWorker.addEventListener('message', handler);

            globalWorker.postMessage({
                type: 'feature-extraction',
                data: texts,
                requestId
            } as MLRequest);
        });
    }, []);

    const groupTexts = useCallback((texts: string[], k: number = 5): Promise<Int32Array> => {
        return new Promise((resolve, reject) => {
            if (!globalWorker) {
                reject('Worker not initialized');
                return;
            }

            const requestId = Math.random().toString(36).substring(7);

            const handler = (event: MessageEvent<MLResponse>) => {
                const { status, data, task, error, requestId: resId, progress } = event.data;

                // IGNORE messages not for this request
                if (resId !== requestId) return;

                if (status === 'complete' && task === 'cluster-texts') {
                    globalWorker?.removeEventListener('message', handler);
                    // Type guard: ensure data is Int32Array
                    if (data instanceof Int32Array) {
                        resolve(data);
                    } else {
                        reject('Invalid data type received from worker');
                    }
                    setStatus('ready');
                } else if (status === 'error') {
                    globalWorker?.removeEventListener('message', handler);
                    reject(error);
                    setError(error || 'Clustering failed');
                    setStatus('error');
                } else if (status === 'working') {
                    setStatus('working');
                    if (progress !== undefined) setProgress(progress);
                }
            };

            globalWorker.addEventListener('message', handler);

            globalWorker.postMessage({
                type: 'cluster-texts',
                data: texts,
                options: { k },
                requestId
            } as MLRequest);
        });
    }, []);

    return {
        generateEmbeddings,
        groupTexts,
        status,
        progress,
        error,
        device,
        resetWorker
    };
};

import { create } from 'zustand';
import * as webllm from "@mlc-ai/web-llm";

// Constants
// Using a small, fast model optimized for browsers.
// Llama-3-8B is great, but might be heavy. Qwen2.5-1.5B is tiny and fast.
// Let's stick to Llama-3.2-1B or 3B if available, otherwise Llama-3-8B-q4.
// Ideally user selects, but we need a default.
// Let's use "Llama-3.2-1B-Instruct-q4f16_1-MLC" for speed/quality balance.
const SELECTED_MODEL = "Llama-3.2-1B-Instruct-q4f16_1-MLC";

interface LLMState {
    engine: webllm.MLCEngineInterface | null;
    isLoading: boolean;
    progress: string;
    error: string | null;
    isReady: boolean;

    // Actions
    initialize: () => Promise<void>;
    generateText: (prompt: string, systemPrompt?: string, options?: { temperature?: number; top_p?: number; max_tokens?: number }) => Promise<string>;

    // Specialized Skills
    generateFilterCode: (columns: string[], userQuery: string, rows?: Record<string, string>[]) => Promise<string>;
    standardizeValues: (uniqueValues: string[]) => Promise<Record<string, string>>;
    enrichRow: (row: Record<string, string>, userPrompt: string) => Promise<string>;

    // New Cleaning Skills
    normalizeDates: (dates: string[]) => Promise<Record<string, string>>;
    normalizeCurrency: (values: string[]) => Promise<Record<string, string>>;
    standardizeStateCodes: (values: string[]) => Promise<Record<string, string>>;
}

// Basic PII Redaction Regex (Client-Side Sanitization)
const PII_EMAIL = /[\w.-]+@[\w.-]+\.\w+/g;
const PII_PHONE = /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g;

export const useWoznyLLM = create<LLMState>((set, get) => ({
    engine: null,
    isLoading: false,
    progress: "",
    error: null,
    isReady: false,

    initialize: async () => {
        if (get().engine || get().isLoading) return;

        set({ isLoading: true, error: null });

        try {
            const initProgressCallback = (report: webllm.InitProgressReport) => {
                set({ progress: report.text });
            };

            const engine = await webllm.CreateMLCEngine(
                SELECTED_MODEL,
                { initProgressCallback }
            );

            set({ engine, isReady: true, isLoading: false, progress: "Ready" });
        } catch (err) {
            const error = err instanceof Error ? err : new Error(String(err));
            set({ error: error.message, isLoading: false });
        }
    },

    generateText: async (prompt, systemPrompt, options) => {
        const engine = get().engine;
        if (!engine) throw new Error("Engine not initialized");

        const messages: webllm.ChatCompletionMessageParam[] = [];
        if (systemPrompt) {
            messages.push({ role: "system", content: systemPrompt });
        }
        messages.push({ role: "user", content: prompt });

        const reply = await engine.chat.completions.create({
            messages,
            temperature: options?.temperature ?? 0.7,
            top_p: options?.top_p,
            max_tokens: options?.max_tokens,
        });

        return reply.choices[0]?.message?.content || "";
    },

    generateFilterCode: async (columns, userQuery, rows = []) => {
        const { generateText } = get();

        // 1. Build Schema Context
        // We want to give the LLM a hint about the data, especially generic "Group" columns.
        let schemaSummary = "AVAILABLE COLUMNS:\n";
        columns.forEach(col => {
            schemaSummary += `- "${col}"`;

            // If we have rows, maybe peek at unique values for "Group" or "Status" columns?
            // Limit to columns with few unique values (categorical)
            if (rows.length > 0) {
                const uniqueValues = new Set<string>();
                for (let i = 0; i < Math.min(rows.length, 500); i++) { // Scan first 500 rows
                    const val = rows[i][col];
                    if (val) {
                        // SANITIZATION: Redact PII from schema context samples
                        let cleanVal = String(val).trim();
                        cleanVal = cleanVal.replace(PII_EMAIL, '[EMAIL_REDACTED]').replace(PII_PHONE, '[PHONE_REDACTED]');
                        uniqueValues.add(cleanVal);
                    }
                    if (uniqueValues.size > 10) break; // Too many values, ignore
                }

                if (uniqueValues.size > 0 && uniqueValues.size <= 10) {
                    schemaSummary += ` (Values: ${Array.from(uniqueValues).join(', ')})`;
                }
            }
            schemaSummary += "\n";
        });

        const systemPrompt = `
        You are a JavaScript Logic Generator. 
        Task: Convert user requests into raw arrow functions to filter data.
        Requirement: Output ONLY the arrow function code.

        ${schemaSummary}

        DATA REFERENCE:
        - Missing string: "[MISSING]"
        - Column name mapping: Use EXACT column names from the list above.

        EXAMPLES:
        Input: "show rows with missing data in telephone"
        Output: (row) => row["telephone"] === "[MISSING]"

        Input: "filter for Certification_Renewal_Date missing"
        Output: (row) => row["Certification_Renewal_Date"] === "[MISSING]"

        Input: "find blank entries in Ethnicity"
        Output: (row) => row["Ethnicity"] === "[MISSING]"

        Input: "Show me missing in Certification_Renewal_Date"
        Output: (row) => row["Certification_Renewal_Date"] === "[MISSING]"

        Input: "missing in column 4"
        Output: (row) => Object.values(row)[3] === "[MISSING]"

        Input: "Show rows that have a Phone Number"
        Output: (row) => row['Phone'] !== '[MISSING]'

        Input: "Show cluster 1"
        Output: (row) => row['Account Manager Group'] === 'Cluster 1'
        `;

        const response = await generateText(userQuery, systemPrompt, {
            temperature: 0.0, // Minimum randomness
            top_p: 1.0,       // Consider all likely options, but temperature 0.0 will override
            max_tokens: 256,  // Hard limit on output length
        });

        let code = response.trim();

        // Simple markdown cleanup: Remove backticks if the model ignores the "no markdown" rule
        // (Even with temp=0.0, some models are hard-wired to use markdown)
        if (code.startsWith('```')) {
            code = code.replace(/^```(javascript|js)?\s*/i, '').replace(/\s*```$/, '');
        }

        return code.trim();
    },

    standardizeValues: async (uniqueValues) => {
        const { generateText } = get();

        const systemPrompt = `You are a Data Cleaning Assistant.
        You will receive a list of messy text strings.
        Your task is to group them into Standardized Terms.
        Return a JSON Map where keys are the messy string and values are the clean string.
        Return ONLY valid JSON.
        `;

        const prompt = `Values:\n${uniqueValues.join('\n')}`;

        const response = await generateText(prompt, systemPrompt);

        try {
            // Clean markdown
            let jsonStr = response.trim();
            if (jsonStr.startsWith('```json')) jsonStr = jsonStr.replace('```json', '').replace('```', '');
            if (jsonStr.startsWith('```')) jsonStr = jsonStr.replace('```', '').replace('```', '');

            return JSON.parse(jsonStr);
        } catch (e) {
            console.error("Failed to parse LLM JSON", response);
            return {};
        }
    },

    enrichRow: async (row, userPrompt) => {
        const { generateText } = get();

        const systemPrompt = `You are a Data Extraction Expert.
        You will receive a JSON object representing a row of data.
        Your task is to extract or infer a specific value based on the User's Request.
        Return ONLY the extracted value. No explanations.
        User Request: "${userPrompt}"
        `;

        const rowStr = JSON.stringify(row);
        const response = await generateText(rowStr, systemPrompt);

        return response.trim();
    },

    // --- NEW SKILLS ---

    normalizeDates: async (dates) => {
        const { generateText } = get();
        const systemPrompt = `You are a Date Normalization Bot.
        Task: Convert diverse date strings into ISO 8601 format (YYYY-MM-DD).
        Input: A list of date strings.
        Output: A JSON Map { "Original String": "YYYY-MM-DD" }.
        Rules:
        - If invalid or ambiguous, return null.
        - "Jan 1, 2024" -> "2024-01-01"
        - "12/31/23" -> "2023-12-31"
        - Return ONLY JSON.
        `;

        const prompt = `Dates to Fix:\n${dates.join('\n')}`;
        const response = await generateText(prompt, systemPrompt, { temperature: 0.1 }); // Low temp for logic

        try {
            let jsonStr = response.trim();
            if (jsonStr.startsWith('```json')) jsonStr = jsonStr.replace('```json', '').replace('```', '');
            if (jsonStr.startsWith('```')) jsonStr = jsonStr.replace('```', '').replace('```', '');
            return JSON.parse(jsonStr);
        } catch (e) { return {}; }
    },

    normalizeCurrency: async (values) => {
        const { generateText } = get();
        const systemPrompt = `You are a Currency Normalization Bot.
        Task: Clean currency strings to a standard numeric format (1234.56).
        Input: A list of price strings.
        Output: A JSON Map { "Original": "Cleaned" }.
        Rules:
        - Remove symbols ($, €, £).
        - Ensure 2 decimal places if applicable.
        - "1,000.00" -> "1000.00"
        - "$50" -> "50.00"
        - Return ONLY JSON.
        `;

        const prompt = `Values to Fix:\n${values.join('\n')}`;
        const response = await generateText(prompt, systemPrompt, { temperature: 0.1 });

        try {
            let jsonStr = response.trim();
            if (jsonStr.startsWith('```json')) jsonStr = jsonStr.replace('```json', '').replace('```', '');
            if (jsonStr.startsWith('```')) jsonStr = jsonStr.replace('```', '').replace('```', '');
            return JSON.parse(jsonStr);
        } catch (e) { return {}; }
    },

    standardizeStateCodes: async (values) => {
        const { generateText } = get();
        const systemPrompt = `You are a US Geography Bot.
        Task: Convert State names to 2-Letter ISO Codes (New York -> NY).
        Input: List of state names/codes.
        Output: JSON Map { "Original": "Code" }.
        Rules:
        - "California" -> "CA"
        - "mass." -> "MA"
        - "NY" -> "NY" (Keep as is)
        - Return ONLY JSON.
        `;

        const prompt = `States to Fix:\n${values.join('\n')}`;
        const response = await generateText(prompt, systemPrompt, { temperature: 0.1 });

        try {
            let jsonStr = response.trim();
            if (jsonStr.startsWith('```json')) jsonStr = jsonStr.replace('```json', '').replace('```', '');
            if (jsonStr.startsWith('```')) jsonStr = jsonStr.replace('```', '').replace('```', '');
            return JSON.parse(jsonStr);
        } catch (e) { return {}; }
    }
}));

import { RowData } from "./store/useWoznyStore";
import { AnalysisIssue } from "./store/useAnalysisStore";
import {
  US_STATES,
  US_STATES_FULL,
  toTitleCase,
  applyDictionary,
  normalizeDate,
  normalizeCurrency,
  ColumnContext,
} from "./normalizers";

// --- CONSTANTS & REGEX ---
const ISO_DATE_REGEX = /^\d{4}-\d{2}-\d{2}$/;
const NON_ISO_DATE_REGEX =
  /^(?:\d{1,2}[-/]\d{1,2}[-/]\d{2,4})|(?:\b(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]* \d{1,2}(?:st|nd|rd|th)?,? \d{4})$/i;
const CURRENCY_SYMBOL_REGEX = /[$€£¥₿]/;
const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/i;
const BROKEN_URL_REGEX = /^(www\.|[a-z0-9](d+[a-z0-9])+\.[a-z]{2,})/i;

// --- UTILITIES ---

export const getColumnContext = (
  values: string[],
  columnName: string,
): ColumnContext => {
  const lo = columnName.toLowerCase();
  if (lo.includes("city") || lo.includes("borough") || lo.includes("town"))
    return "CITY";
  if (lo.includes("state") || lo === "st" || lo.includes("code"))
    return "STATE";

  const sample = values.slice(0, 50).filter(Boolean);
  if (sample.length === 0) return "GENERAL";

  const stateMatches = sample.filter((v) => /^[A-Z]{2}$/.test(v)).length;
  return stateMatches > sample.length * 0.7 ? "STATE" : "GENERAL";
};

// --- ANALYSIS & FIXING ---

export const autoFixRow = (
  row: RowData,
  columns: string[],
  rowIssues: AnalysisIssue[],
): RowData => {
  const newRow = { ...row };
  columns.forEach((col) => {
    let val = String(newRow[col] || "")
      .trim()
      .replace(/\s+/g, " ");
    if (!val || (val.startsWith("[") && val.endsWith("]"))) return;
    if (!rowIssues.some((i) => i.column === col && i.issueType === "FORMAT"))
      return;

    const loCol = col.toLowerCase();
    const context = getColumnContext([], col);

    if (loCol.includes("email")) val = val.toLowerCase();
    else if (loCol.match(/phone|tel|cell/))
      val = val
        .replace(/\D/g, "")
        .replace(/(\d{3})(\d{3})(\d{4})/, "($1) $2-$3");
    else if (loCol.match(/state|^st$|_state/)) {
      val =
        val.length === 2
          ? val.toUpperCase()
          : US_STATES_FULL[val.toLowerCase()] || val;
    } else if (loCol.match(/date|dob|start|end|joined/))
      val = normalizeDate(val);
    else if (loCol.match(/price|cost|amount|fee|revenue|salary/))
      val = normalizeCurrency(val);
    else if (
      loCol.match(
        /name|address|city|street|company|borough|role|dept|title|status|method|payment|category|type|industry|product|service|gender|level|group|source|country|region|county|brand|model|color|material|tag|office|position|org/,
      )
    ) {
      val = toTitleCase(applyDictionary(val, context));
    }
    newRow[col] = val;
  });
  return newRow;
};

// Shared Duplicate Detection Logic
export const findDuplicateGroups = (
  rows: RowData[],
  columns: string[],
): number[][] => {
  const groups: number[][] = [];
  const processedRows = new Set<number>();

  // 1. Exact Duplicates
  const exactMap = new Map<string, number[]>();
  rows.forEach((row, idx) => {
    const finger = columns
      .map((c) =>
        String(row[c] || "")
          .trim()
          .toLowerCase(),
      )
      .join("|");
    if (!exactMap.has(finger)) exactMap.set(finger, []);
    exactMap.get(finger)!.push(idx);
  });

  exactMap.forEach((indices) => {
    if (indices.length > 1) {
      groups.push(indices);
      indices.forEach((i) => processedRows.add(i));
    }
  });

  // 2. Partial Duplicates
  const keyCols = columns.filter((c) => {
    const lo = c.toLowerCase();
    return (
      lo.includes("email") ||
      lo.includes("phone") ||
      (lo.includes("name") && !lo.includes("last"))
    );
  });

  if (keyCols.length > 0) {
    keyCols.forEach((keyCol) => {
      const keyMap = new Map<string, number[]>();
      rows.forEach((row, idx) => {
        if (processedRows.has(idx)) return; // Skip if already grouped
        const val = String(row[keyCol] || "")
          .trim()
          .toLowerCase();
        if (!val || val.length < 3) return;

        if (!keyMap.has(val)) keyMap.set(val, []);
        keyMap.get(val)!.push(idx);
      });

      keyMap.forEach((indices) => {
        if (indices.length > 1) {
          groups.push(indices);
          indices.forEach((i) => processedRows.add(i));
        }
      });
    });
  }

  return groups;
};

export const runDeterministicAnalysis = (
  rows: RowData[],
  columns: string[],
): AnalysisIssue[] => {
  const issues: AnalysisIssue[] = [];
  const contexts: Record<string, ColumnContext> = {};
  columns.forEach(
    (c) =>
      (contexts[c] = getColumnContext(
        rows.map((r) => String(r[c] || "")),
        c,
      )),
  );

  // Duplicate Check using shared logic
  const duplicateGroups = findDuplicateGroups(rows, columns);
  duplicateGroups.forEach((group) => {
    group.forEach((idx, i) => {
      issues.push({
        rowId: idx,
        column: columns[0],
        issueType: "DUPLICATE",
        suggestion: i === 0 ? "Original" : "Duplicate Row",
      });
    });
  });

  // Per-Cell Logic
  rows.forEach((row, idx) => {
    columns.forEach((col) => {
      const val = String(row[col] || "").trim();
      const loVal = val.toLowerCase();
      const loCol = col.toLowerCase();

      if (
        !val ||
        ["null", "n/a", "undefined", "missing", "tbd"].includes(
          loVal.replace(/[\[\]]/g, ""),
        )
      ) {
        issues.push({
          rowId: idx,
          column: col,
          issueType: "MISSING",
          suggestion: `Missing ${col}`,
        });
        return;
      }

      // Formatting Checks
      if (loCol.match(/phone|tel|cell/) && !/^\(\d{3}\) \d{3}-\d{4}$/.test(val))
        issues.push({
          rowId: idx,
          column: col,
          issueType: "FORMAT",
          suggestion: "Standardize Phone",
        });
      else if (
        loCol.match(/date|dob|start|end|joined/) &&
        !ISO_DATE_REGEX.test(val)
      )
        issues.push({
          rowId: idx,
          column: col,
          issueType: "FORMAT",
          suggestion: "Use YYYY-MM-DD",
        });
      else if (
        loCol.match(/price|cost|amount|fee|revenue|salary/) &&
        (CURRENCY_SYMBOL_REGEX.test(val) ||
          !/^-?\d+\.\d{2}$/.test(val.replace(/[$,€£¥\s,]/g, "")))
      ) {
        issues.push({
          rowId: idx,
          column: col,
          issueType: "FORMAT",
          suggestion: "Standardize Currency",
        });
      } else if (loCol.match(/state|^st$|_state/)) {
        if (val.length === 2 && !US_STATES.has(val.toUpperCase()))
          issues.push({
            rowId: idx,
            column: col,
            issueType: "VALIDITY",
            suggestion: "Invalid State",
          });
        else if (val.length > 2 && US_STATES_FULL[loVal])
          issues.push({
            rowId: idx,
            column: col,
            issueType: "FORMAT",
            suggestion: "Use 2-letter Code",
          });
      } else if (loCol.match(/url|website|link/) && !URL_REGEX.test(val))
        issues.push({
          rowId: idx,
          column: col,
          issueType: "FORMAT",
          suggestion: "Fix URL",
        });
      else if (/[a-zA-Z]/.test(val)) {
        const normalized = toTitleCase(applyDictionary(val, contexts[col]));
        if (val !== normalized)
          issues.push({
            rowId: idx,
            column: col,
            issueType: "FORMAT",
            suggestion: "Fix Casing/Abbr",
          });
      }
    });
  });

  return issues;
};

/// <reference lib="dom" />

// wa-sqlite — synchronous OPFS VFS (no Asyncify required)
import * as SQLite from "wa-sqlite";
import SQLiteFactory from "wa-sqlite/dist/wa-sqlite.mjs";
import { AccessHandlePoolVFS } from "wa-sqlite/src/examples/AccessHandlePoolVFS.js";

import type { DBRequest, DBResponse } from "./types";
import { MIGRATIONS, SCHEMA_VERSION } from "./migrations";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/** Directory inside OPFS where the pool files are stored. */
const OPFS_DIRECTORY = "/wozny-db";

/** The SQLite database filename. */
const DB_FILENAME = "wozny.db";

// ---------------------------------------------------------------------------
// Module-level state
// ---------------------------------------------------------------------------

let sqlite3: SQLiteAPI | null = null;
let db: number | null = null;

// ---------------------------------------------------------------------------
// Initialisation
// ---------------------------------------------------------------------------

async function initDB(): Promise<void> {
  if (sqlite3 !== null && db !== null) return; // already initialised

  // 1. Boot the Emscripten WASM module.
  //    locateFile redirects the runtime fetch to /wa-sqlite.wasm which is
  //    served from the Next.js public/ directory as a static asset.
  const module = await (
    SQLiteFactory as unknown as (opts: {
      locateFile: (f: string) => string;
    }) => Promise<unknown>
  )({
    locateFile: (f: string) => `${self.location.origin}/${f}`,
  });

  // 2. Wrap the low-level module in the wa-sqlite JS API.
  sqlite3 = SQLite.Factory(
    module as Parameters<typeof SQLite.Factory>[0],
  ) as SQLiteAPI;

  // 3. Initialise the OPFS VFS.
  //    AccessHandlePoolVFS uses createSyncAccessHandle() — synchronous I/O,
  //    no SharedArrayBuffer or COEP required at the VFS level.
  const vfs = new AccessHandlePoolVFS(OPFS_DIRECTORY);
  await vfs.isReady;

  // 4. Register as the default VFS for this worker.
  sqlite3.vfs_register(vfs as unknown as SQLiteVFS, true);

  // 5. Open (or create) the database file.
  db = await sqlite3.open_v2(DB_FILENAME);

  // 6. Run any pending schema migrations.
  await runMigrations();

  console.log("[db.worker] Initialised. OPFS directory:", OPFS_DIRECTORY);
}

// ---------------------------------------------------------------------------
// Migrations
// ---------------------------------------------------------------------------

async function runMigrations(): Promise<void> {
  if (!sqlite3 || db === null) throw new Error("DB not initialised");

  // Determine which version is currently applied.
  // If db_version doesn't exist yet this query will throw, so we catch
  // and treat that as "no migrations applied" (version 0).
  let currentVersion = 0;
  try {
    const rows = await querySQL("SELECT MAX(version) as v FROM db_version");
    const v = rows[0]?.v;
    if (typeof v === "number") currentVersion = v;
  } catch {
    // Table doesn't exist yet — start from version 0.
    currentVersion = 0;
  }

  if (currentVersion >= SCHEMA_VERSION) {
    console.log("[db.worker] Schema up to date at version", currentVersion);
    return;
  }

  // Apply each missing version in ascending order.
  const versions = Object.keys(MIGRATIONS)
    .map(Number)
    .filter((v) => v > currentVersion)
    .sort((a, b) => a - b);

  for (const version of versions) {
    console.log("[db.worker] Applying migration v" + version);
    for (const sql of MIGRATIONS[version]) {
      await execSQL(sql);
    }
    await execSQL(
      "INSERT INTO db_version (version, applied_at) VALUES (?, ?)",
      [version, new Date().toISOString()],
    );
    console.log("[db.worker] Migration v" + version + " applied.");
  }
}

// ---------------------------------------------------------------------------
// SQL helpers
// ---------------------------------------------------------------------------

async function execSQL(
  sql: string,
  bind?: (string | number | null)[],
): Promise<void> {
  if (!sqlite3 || db === null) throw new Error("DB not initialised");

  for await (const stmt of sqlite3.statements(db, sql)) {
    if (bind && bind.length > 0) {
      sqlite3.bind_collection(stmt, bind);
    }
    // Drain any rows (handles DDL, DML, and no-result SELECT alike).
    while ((await sqlite3.step(stmt)) === SQLite.SQLITE_ROW) {
      /* drain */
    }
  }
}

async function querySQL(
  sql: string,
  bind?: (string | number | null)[],
): Promise<Record<string, unknown>[]> {
  if (!sqlite3 || db === null) throw new Error("DB not initialised");

  const results: Record<string, unknown>[] = [];

  for await (const stmt of sqlite3.statements(db, sql)) {
    if (bind && bind.length > 0) {
      sqlite3.bind_collection(stmt, bind);
    }

    while ((await sqlite3.step(stmt)) === SQLite.SQLITE_ROW) {
      const names = sqlite3.column_names(stmt);
      const values = sqlite3.row(stmt);
      const row: Record<string, unknown> = {};
      names.forEach((name, i) => {
        row[name] = values[i];
      });
      results.push(row);
    }
  }

  return results;
}

// ---------------------------------------------------------------------------
// Message handler
// ---------------------------------------------------------------------------

self.onmessage = async (event: MessageEvent<DBRequest>) => {
  const { id, type, sql, bind } = event.data;

  const reply = (payload: Omit<DBResponse, "id">) => {
    (self as unknown as Worker).postMessage({
      id,
      ...payload,
    } satisfies DBResponse);
  };

  try {
    switch (type) {
      case "INIT": {
        await initDB();
        reply({ type: "INIT_OK" });
        break;
      }

      case "EXEC": {
        if (!sql) throw new Error("EXEC requires a sql string");
        await execSQL(sql, bind);
        reply({ type: "EXEC_OK" });
        break;
      }

      case "EXEC_BATCH": {
        const { statements } = event.data;
        if (!statements || !Array.isArray(statements)) {
          throw new Error("EXEC_BATCH requires a statements array");
        }
        await execSQL("BEGIN");
        try {
          for (const { sql: bsql, bind: bbind } of statements) {
            await execSQL(bsql, bbind);
          }
          await execSQL("COMMIT");
        } catch (batchErr) {
          await execSQL("ROLLBACK").catch(() => {});
          throw batchErr;
        }
        reply({ type: "EXEC_BATCH_OK" });
        break;
      }

      case "QUERY": {
        if (!sql) throw new Error("QUERY requires a sql string");
        const rows = await querySQL(sql, bind);
        reply({ type: "QUERY_OK", rows });
        break;
      }

      default: {
        throw new Error(`Unknown message type: ${type}`);
      }
    }
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    console.error("[db.worker] Error handling", type, ":", message);
    reply({ type: "ERROR", error: message });
  }
};

// ---------------------------------------------------------------------------
// persistence.ts — write-path subscriber for OPFS SQLite
//
// Imported once as a side-effect (import '@/lib/db/persistence') from the
// app root. Sets up a Zustand subscriber that mirrors useWoznyStore mutations
// to the OPFS database in the background.
//
// Design decisions:
//  - Fire-and-forget async writes: store mutations remain synchronous and
//    the UI never waits for the DB. Errors are logged, never thrown to React.
//  - Full clean-row replacement: when rows change, delete-and-reinsert all
//    clean rows inside a single transaction via execBatch. Simpler than
//    diffing, and SQLite handles it fast enough for typical CSV sizes.
//  - 500 ms debounce on row writes: prevents a flood of DB writes during
//    rapid cell edits or bulk operations.
//  - Metadata writes are immediate (cheap single-row upsert).
// ---------------------------------------------------------------------------

import { useWoznyStore, RowData, WoznyState } from "../store/useWoznyStore";
import { useAnalysisStore } from "../store/useAnalysisStore";
import { exec, execBatch, query, initDB, getAllSessions, getActiveSession, getSessionById, activateSession } from "./db";
import type { DBStatement } from "./types";

// ---------------------------------------------------------------------------
// Ignored-column write helper (used by the analysisStore subscriber below)
// ---------------------------------------------------------------------------

async function writeIgnoredColumns(
  sessionId: number,
  columns: string[],
): Promise<void> {
  const statements: DBStatement[] = [
    {
      sql: `DELETE FROM ignored_columns WHERE session_id = ?`,
      bind: [sessionId],
    },
    ...columns.map((col) => ({
      sql: `INSERT INTO ignored_columns (session_id, column_name) VALUES (?, ?)`,
      bind: [sessionId, col] as (string | number | null)[],
    })),
  ];
  await execBatch(statements);
}

// ---------------------------------------------------------------------------
// Session tracking
// ---------------------------------------------------------------------------

/** The SQLite id of the currently active session, or null before first upload. */
let currentSessionId: number | null = null;

/**
 * Set to true while rehydrateSession() is populating the stores.
 * Prevents the write-path subscriber from treating rehydration as a
 * new-file upload or a user mutation and writing straight back to the DB.
 */
let isRehydrating = false;

/**
 * Internal helper to get the current session ID.
 * Used internally by persistence logic to track which session is active.
 * 
 * Note: This is intentionally not exported. UI components should query
 * session information directly from the database using the db.ts API
 * (e.g., getActiveSession()) rather than relying on this internal state.
 * 
 * @internal
 * @returns The current session ID, or null if no session is active
 */
function getCurrentSessionId(): number | null {
  return currentSessionId;
}

// ---------------------------------------------------------------------------
// Debounce state
// ---------------------------------------------------------------------------

const ROW_WRITE_DEBOUNCE_MS = 500;
let rowDebounceTimer: ReturnType<typeof setTimeout> | null = null;

// ---------------------------------------------------------------------------
// Low-level DB helpers
// ---------------------------------------------------------------------------

async function createSession(fileName: string): Promise<number> {
  await exec(
    `INSERT INTO sessions (file_name, is_active, created_at, updated_at)
     VALUES (?, 1, datetime('now'), datetime('now'))`,
    [fileName],
  );
  const rows = await query<{ id: number }>(`SELECT last_insert_rowid() AS id`);
  return rows[0].id;
}

async function deactivateAllSessions(): Promise<void> {
  await exec(`UPDATE sessions SET is_active = 0, updated_at = datetime('now')`);
}

async function upsertDatasetMeta(
  sessionId: number,
  state: WoznyState,
): Promise<void> {
  await exec(
    `INSERT OR REPLACE INTO dataset_meta
       (session_id, columns, column_widths, splittable_columns,
        sort_config, show_hidden_columns)
     VALUES (?, ?, ?, ?, ?, ?)`,
    [
      sessionId,
      JSON.stringify(state.columns),
      JSON.stringify(state.columnWidths),
      JSON.stringify(state.splittableColumns),
      state.sortConfig ? JSON.stringify(state.sortConfig) : null,
      state.showHiddenColumns ? 1 : 0,
    ],
  );
}

function buildRowInsertStatements(
  sessionId: number,
  rowType: "raw" | "clean",
  rows: RowData[],
): DBStatement[] {
  const statements: DBStatement[] = [
    {
      sql: `DELETE FROM dataset_rows
            WHERE session_id = ? AND row_type = ?`,
      bind: [sessionId, rowType],
    },
  ];
  for (let i = 0; i < rows.length; i++) {
    statements.push({
      sql: `INSERT INTO dataset_rows
              (session_id, row_type, row_index, row_json)
            VALUES (?, ?, ?, ?)`,
      bind: [sessionId, rowType, i, JSON.stringify(rows[i])],
    });
  }
  return statements;
}

async function writeRawRows(sessionId: number, rows: RowData[]): Promise<void> {
  await execBatch(buildRowInsertStatements(sessionId, "raw", rows));
}

async function writeCleanRows(
  sessionId: number,
  rows: RowData[],
): Promise<void> {
  await execBatch(buildRowInsertStatements(sessionId, "clean", rows));
}

// ---------------------------------------------------------------------------
// Session lifecycle
// ---------------------------------------------------------------------------

async function handleNewFile(state: WoznyState): Promise<void> {
  await initDB();

  const existingSessions = await getAllSessions();

  // Note: Session selection UI not yet implemented. See TODO.md for details.
  // Currently always creates a new session regardless of existing sessions.

  if (existingSessions.length > 0) {
    console.log(
      "[persistence] Existing sessions found. Creating new session (UI prompt not yet implemented).",
    );
  } else {
    console.log(
      "[persistence] No existing sessions found. Creating new session.",
    );
  }

  // Deactivate any previously active session before creating the new one.
  await deactivateAllSessions();

  const id = await createSession(state.fileName ?? "Untitled");
  currentSessionId = id;

  // Reset in-memory ignored columns.
  if (useAnalysisStore.getState().ignoredColumns.length > 0) {
    useAnalysisStore.getState().resetIgnoredColumns([]);
  }

  // Write metadata, raw rows, and clean rows.
  await upsertDatasetMeta(id, state);
  await writeRawRows(id, state.rawRows);
  await writeCleanRows(id, state.rows);

  console.log(
    "[persistence] New session created:",
    id,
    "file:",
    state.fileName,
  );
}

// ---------------------------------------------------------------------------
// Debounced write helpers
// ---------------------------------------------------------------------------

function scheduleCleanRowWrite(sessionId: number, rows: RowData[]): void {
  if (rowDebounceTimer !== null) clearTimeout(rowDebounceTimer);
  rowDebounceTimer = setTimeout(() => {
    rowDebounceTimer = null;
    writeCleanRows(sessionId, rows).catch((err) =>
      console.error("[persistence] Clean row write failed:", err),
    );
  }, ROW_WRITE_DEBOUNCE_MS);
}

// ---------------------------------------------------------------------------
// Main subscriber
// ---------------------------------------------------------------------------

async function handleStateChange(
  state: WoznyState,
  prevState: WoznyState,
): Promise<void> {
  // ── New file uploaded ────────────────────────────────────────────────────
  // fileName changes from null → string or from one filename to another.
  if (state.fileName !== prevState.fileName && state.fileName !== null) {
    await handleNewFile(state);
    return;
  }

  // ── No active session — nothing to persist yet ───────────────────────────
  if (currentSessionId === null) return;

  // ── Clean rows mutated ───────────────────────────────────────────────────
  // Covers: updateCell, removeRow, resolveDuplicates, bulkUpdate,
  //         addColumn, splitAddressColumn.
  // The reference inequality check is cheap — immer always produces a new
  // array reference when any row or column changes.
  if (state.rows !== prevState.rows) {
    scheduleCleanRowWrite(currentSessionId, state.rows);
  }

  // ── Structural metadata changed ──────────────────────────────────────────
  // Covers: addColumn (columns + columnWidths + splittableColumns),
  //         splitAddressColumn (same), toggleSort (sortConfig),
  //         toggleShowHiddenColumns (showHiddenColumns).
  if (
    state.columns !== prevState.columns ||
    state.columnWidths !== prevState.columnWidths ||
    state.splittableColumns !== prevState.splittableColumns ||
    state.sortConfig !== prevState.sortConfig ||
    state.showHiddenColumns !== prevState.showHiddenColumns
  ) {
    upsertDatasetMeta(currentSessionId, state).catch((err) =>
      console.error("[persistence] Metadata write failed:", err),
    );
  }
}

// ---------------------------------------------------------------------------
// Activate the subscriber
//
// Called immediately when this module is imported. The subscriber is a
// lightweight synchronous wrapper — the real async work happens inside
// handleStateChange, so the Zustand notify loop is never blocked.
// ---------------------------------------------------------------------------

/**
 * Helper to wrap Zustand subscribers with rehydration guard.
 * Prevents write-path subscribers from firing during rehydration.
 */
function createGuardedSubscriber<T>(
  handler: (state: T, prevState: T) => void | Promise<void>
): (state: T, prevState: T) => void {
  return (state, prevState) => {
    if (isRehydrating) return;
    const result = handler(state, prevState);
    if (result instanceof Promise) {
      result.catch((err) => console.error("[persistence] Subscriber error:", err));
    }
  };
}

useWoznyStore.subscribe(
  createGuardedSubscriber((state, prevState) => {
    return handleStateChange(state, prevState);
  })
);

// Subscribe to useAnalysisStore to persist ignoredColumns changes.
// toggleIgnoreColumn lives in useAnalysisStore, so the useWoznyStore
// subscriber above never sees those mutations.
useAnalysisStore.subscribe(
  createGuardedSubscriber((state, prevState) => {
    if (state.ignoredColumns === prevState.ignoredColumns) return;
    if (currentSessionId === null) return;

    return writeIgnoredColumns(currentSessionId, state.ignoredColumns);
  })
);

// ---------------------------------------------------------------------------
// Rehydration — read path (Phase 3b)
//
// Called once on app mount. Reads the most recent active session from the
// OPFS database and populates useWoznyStore and useAnalysisStore before the
// UI renders any data. Returns true if a session was restored, false if the
// database is empty (first visit or after a clear).
// ---------------------------------------------------------------------------

export async function rehydrateSession(): Promise<boolean> {
  await initDB();

  // 1. Find the most recent active session.
  const activeSession = await getActiveSession();

  if (!activeSession) {
    console.log("[persistence] No active session — starting fresh.");
    return false;
  }

  // 1.5. Fetch all sessions and return them to the caller to display in a list.
  const allSessions = await getAllSessions();

  // If there are no sessions at all, we still return false to indicate
  // that no session was restored. If there are sessions, we return them
  // so the UI can display them.
  if (allSessions.length === 0) {
    console.log("[persistence] No sessions found in the database.");
    return false;
  }

  console.log(
    `[persistence] Found ${allSessions.length} existing sessions. Returning list to caller.`,
  );
  // Note: Session list display not yet implemented. See TODO.md for details.
  // Currently returns false, indicating no session was automatically restored.
  return false;
}

/**
 * Loads a specific session by its ID. This is called when the user selects
 * a session from the list after no active session was found during initial rehydration.
 * @param sessionId The ID of the session to load.
 * @returns True if the session was loaded successfully, false otherwise.
 */
export async function loadSession(sessionId: number): Promise<boolean> {
    await initDB();

    // 1. Activate the session in the database.
    try {
      await activateSession(sessionId);
    } catch (error) {
      console.error("[persistence] Failed to activate session:", error);
      return false;
    }

    // 2. Fetch session details (needed for fileName)
    const session = await getSessionById(sessionId);

    if (!session) {
      console.error(
        "[persistence] Session not found after activation:",
        sessionId,
      );
      return false;
    }
    const { file_name: fileName } = session;

    // 3. Load dataset metadata.
    const metaRows = await query<{
      columns: string;
      column_widths: string;
      splittable_columns: string;
      sort_config: string | null;
      show_hidden_columns: number;
    }>(
      `SELECT columns, column_widths, splittable_columns,
            sort_config, show_hidden_columns
       FROM dataset_meta WHERE session_id = ?`,
      [sessionId],
    );

    if (metaRows.length === 0) {
      console.warn(
        "[persistence] Session",
        sessionId,
        "has no metadata — skipping load.",
      );
      return false;
    }
    const meta = metaRows[0];

    // 4. Load raw rows.
    const rawRecords = await query<{ row_json: string }>(
      `SELECT row_json FROM dataset_rows
     WHERE session_id = ? AND row_type = 'raw'
     ORDER BY row_index`,
      [sessionId],
    );

    // 5. Load clean rows.
    const cleanRecords = await query<{ row_json: string }>(
      `SELECT row_json FROM dataset_rows
     WHERE session_id = ? AND row_type = 'clean'
     ORDER BY row_index`,
      [sessionId],
    );

    const rawRows = rawRecords.map(
      (r) => JSON.parse(String(r.row_json)) as RowData,
    );
    const cleanRows = cleanRecords.map(
      (r) => JSON.parse(String(r.row_json)) as RowData,
    );

    if (cleanRows.length === 0) {
      console.warn(
        "[persistence] Session",
        sessionId,
        "has no rows — skipping load.",
      );
      return false;
    }

    // 6. Load ignored columns.
    const ignoredColRecords = await query<{ column_name: string }>(
      `SELECT column_name FROM ignored_columns WHERE session_id = ?`,
      [sessionId],
    );
    const ignoredColumns = ignoredColRecords.map((r) => String(r.column_name));

    // 7. Populate stores.
    currentSessionId = sessionId;
    isRehydrating = true;

    try {
      useWoznyStore.setState({
        fileName,
        rawRows,
        rows: cleanRows,
        columns: JSON.parse(String(meta.columns)) as string[],
        columnWidths: JSON.parse(String(meta.column_widths)) as Record<
          string,
          number
        >,
        splittableColumns: JSON.parse(
          String(meta.splittable_columns),
        ) as Record<string, "ADDRESS" | "NAME" | "NONE">,
        sortConfig: meta.sort_config
          ? (JSON.parse(String(meta.sort_config)) as WoznyState["sortConfig"])
          : null,
        showHiddenColumns: meta.show_hidden_columns === 1,
        activeTab: "report", // Default to report view after loading
      });

      if (ignoredColumns.length > 0) {
        useAnalysisStore.getState().resetIgnoredColumns(ignoredColumns);
      }
    } finally {
      isRehydrating = false;
    }

    console.log(
      "[persistence] Loaded session",
      sessionId,
      "—",
      fileName,
      "—",
      cleanRows.length,
      "rows",
    );

    return true;
}

