export type SplitType = 'ADDRESS' | 'NAME' | 'NONE';
export interface AddressComponents { Street: string; City: string; State: string; Zip: string; }
export interface NameComponents { First: string; Middle: string; Last: string; }

// Internal Utility to keep UI consistent

// Keywords that suggest a column is Categorical/Business, not a Person's Name
const BUSINESS_KEYWORDS = new Set([
    'corp', 'inc', 'llc', 'group', 'firm', 'public', 'private', 'organization', 'org', 'practice', 'nonprofit', 'company', 'associates', 'limited', 'ltd', 'dept', 'department', 'trust', 'partners'
]);

export const getSplittableType = (values: string[]): SplitType => {
    if (!values?.length) return 'NONE';
    const sample = values.slice(0, 30).filter(Boolean); // Slightly larger sample for cardinality
    if (sample.length < 5) return 'NONE';

    // 1. Cardinality Check (Categorical vs Unique)
    // If we have many repeating values in a small sample, it's definitely Categorical.
    const uniqueValues = new Set(sample.map(v => v.trim().toLowerCase()));
    const uniquenessRatio = uniqueValues.size / sample.length;
    if (uniquenessRatio < 0.7) return 'NONE'; // Too many repeats = Categorical

    let addressCount = 0, nameCount = 0;

    sample.forEach(val => {
        const lo = val.toLowerCase();

        // Address: Ends in Zip OR has Street Suffix
        if (/\b\d{5}(-\d{4})?\b$/.test(val) || /\b(St|Ave|Rd|Blvd|Ln|Dr|Way|Ct|Pl|Street|Avenue|Road)\b/i.test(val)) {
            addressCount++;
        }
        // Name: 2-3 words, no numbers, NO business keywords
        else if (/^[^\d]+$/.test(val)) {
            const parts = val.trim().split(/\s+/);
            const hasBusinessKeyword = parts.some(p => BUSINESS_KEYWORDS.has(p.toLowerCase()));

            if (parts.length >= 2 && parts.length <= 3 && !hasBusinessKeyword) {
                nameCount++;
            }
        }
    });

    if (addressCount > sample.length * 0.4) return 'ADDRESS';
    if (nameCount > sample.length * 0.4) return 'NAME';
    return 'NONE';
};

export const parseFullName = (raw: string): NameComponents | null => {
    if (!raw || raw.length < 2) return null;
    const clean = raw.replace(/\b(Mr|Ms|Mrs|Dr|Prof)\.?\s+/i, '').trim();
    const parts = clean.split(/\s+/).filter(p => p.length > 0);

    const res = {
        First: toTitleCase(parts[0] || ''),
        Middle: parts.length > 2 ? toTitleCase(parts.slice(1, -1).join(' ')) : '',
        Last: toTitleCase(parts[parts.length - 1] || '')
    };
    return res.First ? res : null;
};

export const parseAddress = (raw: string): AddressComponents => {
    const fallback: AddressComponents = { Street: raw, City: '[MISSING]', State: '[MISSING]', Zip: '[MISSING]' };

    // Security: Truncate or reject extremely long strings to prevent ReDoS
    if (!raw || raw.length < 5 || raw.length > 200) return fallback;

    const clean = raw.trim();

    // 1. ZIP ANCHOR STRATEGY (Highest Accuracy)
    const zipMatch = clean.match(/\b(\d{5}(?:-\d{4})?)\b$/);
    if (zipMatch) {
        const zip = zipMatch[1];
        const lookup = ZIP_LOOKUP[zip];
        if (lookup) {
            // HYBRID STRATEGY: 
            // 1. Try to use Suffix Pattern to physically separate Street from "City in Text" (e.g. "Manhattan")
            // This is critical because "text city" (Manhattan) might differ from "lookup city" (New York),
            // and simple string replacement would fail to remove "Manhattan".
            // ROBUSTNESS UPDATE: Added \.? to handle "Blvd." and expanded suffix list (Pkwy, Cir, etc.)
            const suffixMatch = clean.match(/^(.*?\b(?:St|Ave|Rd|Blvd|Dr|Ln|Way|Ct|Pl|Street|Avenue|Road|Pkwy|Cir|Sq|Aly|Hwy)\.?)\s+(.*?)\s+([A-Z]{2})\s+(\d{5}(?:-\d{4})?)$/i);

            if (suffixMatch) {
                // Winning Combo: Accurate Street split + Standardized City from Lookup
                return {
                    Street: toTitleCase(suffixMatch[1].trim()),
                    City: lookup.city, // Normalize "Manhattan" -> "New York"
                    State: lookup.state,
                    Zip: zip
                };
            }

            // 2. Fallback: Try to remove the Canonical City/State from string
            // (Works only if text matches lookup, e.g. "New York" == "New York")
            let street = clean.replace(zip, '').trim();
            street = street.replace(new RegExp(`,?\\s*${lookup.state}\\b`, 'i'), '');
            // Attempt to remove canonical city. If it fails, we return street as-is (imperfect but safe)
            street = street.replace(new RegExp(`,?\\s*${lookup.city}\\b`, 'i'), '').replace(/,$/, '');

            return { Street: toTitleCase(street) || '[MISSING]', City: lookup.city, State: lookup.state, Zip: zip };
        }

        // 1b. Suffix-Aware Pattern Fallback
        // Matches: "222 Main St Brooklyn NY 11215"
        // Anchor on common street suffixes to separate street from city accurately.
        // ROBUSTNESS UPDATE: Added \.? and expanded list
        const suffixMatch = clean.match(/^(.*?\b(?:St|Ave|Rd|Blvd|Dr|Ln|Way|Ct|Pl|Street|Avenue|Road|Pkwy|Cir|Sq|Aly|Hwy)\.?)\s+(.*?)\s+([A-Z]{2})\s+(\d{5}(?:-\d{4})?)$/i);
        if (suffixMatch && US_STATES.has(suffixMatch[3].toUpperCase())) {
            return {
                Street: toTitleCase(suffixMatch[1].trim()),
                City: toTitleCase(suffixMatch[2].trim()) || '[MISSING]',
                State: suffixMatch[3].toUpperCase(),
                Zip: zip
            };
        }

        // 1c. Simple Pattern Fallback (Greedy Street, One Word City)
        // Matches: "123 Main Brooklyn NY 11215"
        // SECURITY UPDATE: Changed (.*) to (.*?) non-greedy match to prevent catastrophic backtracking
        const generalMatch = clean.match(/^(.*?)\s+([^,0-9\s]+)\s+([A-Z]{2})\s+(\d{5}(?:-\d{4})?)$/i);
        if (generalMatch && US_STATES.has(generalMatch[3].toUpperCase())) {
            return {
                Street: toTitleCase(generalMatch[1].trim()),
                City: toTitleCase(generalMatch[2].trim()),
                State: generalMatch[3].toUpperCase(),
                Zip: zip
            };
        }
    }

    // 2. COMMA DELIMITED STRATEGY
    const parts = clean.split(',').map(s => s.trim());
    if (parts.length >= 3) {
        return {
            Street: toTitleCase(parts.slice(0, parts.length - 2).join(', ')),
            City: toTitleCase(parts[parts.length - 2]),
            State: parts[parts.length - 1].toUpperCase().slice(0, 2),
            Zip: zipMatch ? zipMatch[1] : '[MISSING]'
        };
    }

    return fallback;
};

export const smartSplitColumn = (rows: Record<string, string>[], columnName: string, type: SplitType) => {
    const results = rows.map(row => {
        const val = row[columnName];
        if (!val) return null;
        return type === 'ADDRESS' ? parseAddress(val) : type === 'NAME' ? parseFullName(val) : null;
    });

    return {
        successCount: results.filter(r => r && !Object.values(r).includes('[MISSING]')).length,
        failCount: results.filter(r => !r || Object.values(r).includes('[MISSING]')).length,
        results
    };
};

import { create } from "zustand";
import { immer } from "zustand/middleware/immer";
import { useWoznyStore, RowData } from "./useWoznyStore";
import { runDeterministicAnalysis, autoFixRow } from "../data-quality";

export interface AnalysisIssue {
  rowId: number;
  column: string;
  issueType: "FORMAT" | "DUPLICATE" | "MISSING" | "VALIDITY";
  suggestion: string;
}

interface AnalysisState {
  issues: AnalysisIssue[];
  ignoredColumns: string[];
  isAnalyzing: boolean;

  // Actions
  setIssues: (issues: AnalysisIssue[]) => void;
  toggleIgnoreColumn: (columnId: string) => void;
  /** Replaces ignoredColumns wholesale — used by rehydration only. */
  resetIgnoredColumns: (columns: string[]) => void;
  autoFormat: () => void;
  runAnalysis: () => void;
}

export const useAnalysisStore = create<AnalysisState>()(
  immer((set, get) => ({
    issues: [],
    ignoredColumns: [],
    isAnalyzing: false,

    setIssues: (issues) =>
      set((state) => {
        state.issues = issues;
      }),

    resetIgnoredColumns: (columns) =>
      set((state) => {
        state.ignoredColumns = columns;
      }),

    toggleIgnoreColumn: (columnId) =>
      set((state) => {
        if (state.ignoredColumns.includes(columnId)) {
          state.ignoredColumns = state.ignoredColumns.filter(
            (c) => c !== columnId,
          );
        } else {
          state.ignoredColumns.push(columnId);
        }
      }),

    autoFormat: () => {
      const woznyStore = useWoznyStore.getState();
      const { issues } = get();

      // We need to update the main store rows, but logic is here
      // Option 1: Call a generic updateRows action on WoznyStore
      // Option 2: Compute new rows here and sending them back

      const newRows = woznyStore.rows.map((row, idx) => {
        const rowIssues = issues.filter((i) => i.rowId === idx);
        return autoFixRow(row, woznyStore.columns, rowIssues);
      });

      // Update Main Store
      woznyStore.setRows(newRows);

      // Re-run analysis immediately
      get().runAnalysis();
    },

    runAnalysis: () => {
      const { rows, columns } = useWoznyStore.getState();
      // In a real app this might be async / web worker
      const issues = runDeterministicAnalysis(rows, columns);
      set({ issues });
    },
  })),
);

// Subscription: Auto-analyze when rows change
useWoznyStore.subscribe((state, prevState) => {
  if (state.rows !== prevState.rows || state.columns !== prevState.columns) {
    useAnalysisStore.getState().runAnalysis();
  }
});

/**
 * Checks if the current environment supports WebGPU.
 * Returns true if supported, false otherwise.
 */
export const checkWebGPU = async (): Promise<boolean> => {
    if (typeof navigator === 'undefined') return false; // Server-side
    if (!navigator.gpu) return false;

    try {
        const adapter = await navigator.gpu.requestAdapter();
        return !!adapter;
    } catch (e) {
        return false;
    }
};

'use client';

import React, { useRef } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { RowData } from '@/lib/store/useWoznyStore';
import clsx from 'clsx';

import { Trash2, Eye, EyeOff, Scissors, ArrowUp, ArrowDown } from 'lucide-react';

interface DataGridProps {
    data: RowData[];
    columns: string[];
    className?: string;
    onCellClick?: (rowIndex: number, columnId: string, value: string) => void;
    onDeleteRow?: (rowIndex: number) => void;
    issueMap?: Record<number, Record<string, string>>;
    rowStateMap?: Record<number, 'DUPLICATE' | 'MULTIPLE' | 'Loading'>;
    ignoredColumns?: string[];
    onToggleIgnore?: (col: string) => void;
    onSplitColumn?: (col: string) => void;
    splittableColumns?: Record<string, 'ADDRESS' | 'NAME' | 'NONE'>;
    columnWidths?: Record<string, number>;
    sortConfig?: { columnId: string; direction: 'asc' | 'desc' } | null;
    onSort?: (col: string) => void;
}

export const DataGrid = React.forwardRef<HTMLDivElement, DataGridProps>(({
    data, columns, className, onCellClick, onDeleteRow, issueMap, rowStateMap,
    ignoredColumns = [], onToggleIgnore, onSort, onSplitColumn, splittableColumns = {}, columnWidths = {}, sortConfig
}, ref) => {
    const defaultRef = useRef<HTMLDivElement>(null);
    const parentRef = (ref as React.RefObject<HTMLDivElement>) || defaultRef;

    const rowVirtualizer = useVirtualizer({
        count: data.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 40,
        overscan: 10,
    });

    const HEADER_HEIGHT = 56;

    // Smart Column Sizing Heuristic
    const getColumnWidth = (col: string) => {
        // Source of Truth: Store-calculated dynamic widths
        if (columnWidths[col]) return columnWidths[col];

        const lower = col.toLowerCase();
        if (lower.includes('address') || lower.includes('description') || lower.includes('note') || lower.includes('summary')) return 320;
        if (lower.includes('email') || lower.includes('url') || lower.includes('link') || lower.includes('title')) return 240;

        // Name Logic
        if (lower.includes('manager')) return 200; // Account Manager usually long
        if (lower === 'name' || lower === 'full name' || lower === 'fullname') return 200;
        if (lower.includes('name')) return 140; // First Name, Last Name -> Narrower

        if (lower.includes('state') || lower.includes('zip') || lower.includes('year') || lower.includes('id') || lower === 'xx') return 100;
        if (lower.includes('phone') || lower.includes('date')) return 140;
        return 180; // Default
    };

    return (
        <div
            ref={parentRef}
            className={clsx("w-full h-full overflow-auto bg-white dark:bg-neutral-900 border rounded-lg border-neutral-200 dark:border-neutral-800", className)}
        >
            <div
                style={{
                    height: `${rowVirtualizer.getTotalSize() + HEADER_HEIGHT}px`,
                    width: '100%',
                    position: 'relative',
                }}
                className="min-w-max"
            >
                {/* Header Row (Sticky) */}
                <div
                    style={{ height: HEADER_HEIGHT }}
                    className="sticky top-0 z-10 flex bg-neutral-100 dark:bg-neutral-900 border-b border-neutral-200 dark:border-neutral-700 font-medium text-neutral-500 dark:text-neutral-400 text-sm box-border"
                >
                    {columns.map((col) => {
                        const isIgnored = ignoredColumns.includes(col);
                        const width = getColumnWidth(col);
                        const isSorted = sortConfig?.columnId === col;
                        const direction = isSorted ? sortConfig.direction : null;

                        return (
                            <div
                                key={col}
                                style={{ width }}
                                className={clsx(
                                    "shrink-0 border-r border-neutral-200 dark:border-neutral-800 last:border-r-0 flex items-center justify-between px-3 group transition-colors",
                                    onSort && "cursor-pointer hover:bg-neutral-200/50 dark:hover:bg-neutral-800/50"
                                )}
                                onClick={() => onSort?.(col)}
                            >
                                <div className="flex items-center gap-1.5 overflow-hidden">
                                    <span className={clsx("whitespace-normal line-clamp-2 leading-tight py-1", isIgnored && "opacity-50 line-through")}>
                                        {col.split('_').join('_\u200B')}
                                    </span>
                                    {direction === 'asc' && <ArrowUp className="w-3.5 h-3.5 text-blue-600 dark:text-blue-400 shrink-0" />}
                                    {direction === 'desc' && <ArrowDown className="w-3.5 h-3.5 text-blue-600 dark:text-blue-400 shrink-0" />}
                                </div>

                                <div className="flex items-center shrink-0">
                                    {onSplitColumn && splittableColumns[col] && splittableColumns[col] !== 'NONE' && (
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                onSplitColumn(col);
                                            }}
                                            className="text-neutral-400 hover:text-purple-600 dark:hover:text-purple-400 p-1 rounded-full hover:bg-neutral-200 dark:hover:bg-neutral-800 transition-all opacity-0 group-hover:opacity-100 focus:opacity-100 mr-1"
                                            title={`Smart Split ${splittableColumns[col] === 'ADDRESS' ? 'Address' : 'Name'}`}
                                        >
                                            <Scissors className="w-4 h-4" />
                                        </button>
                                    )}

                                    {onToggleIgnore && (
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                onToggleIgnore(col);
                                            }}
                                            className="text-neutral-400 hover:text-neutral-600 dark:hover:text-neutral-200 p-1 rounded-full hover:bg-neutral-200 dark:hover:bg-neutral-800 transition-all opacity-0 group-hover:opacity-100 focus:opacity-100"
                                            title={isIgnored ? "Restore Column" : "Ignore Column"}
                                        >
                                            {isIgnored ? (
                                                <EyeOff className="w-4 h-4 text-red-500" />
                                            ) : (
                                                <Eye className="w-4 h-4" />
                                            )}
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                    {onDeleteRow && (
                        <div className="p-3 w-12 shrink-0 border-l border-neutral-200 dark:border-neutral-800 flex items-center justify-center sticky right-0 bg-neutral-100 dark:bg-neutral-900">
                            <span className="sr-only">Actions</span>
                        </div>
                    )}
                </div>

                {/* Virtualized Rows */}
                {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                    const row = data[virtualRow.index];
                    const rowIssues = issueMap ? issueMap[virtualRow.index] : {};
                    const rowState = rowStateMap ? rowStateMap[virtualRow.index] : null;

                    return (
                        <div
                            key={virtualRow.key}
                            style={{
                                position: 'absolute',
                                top: 0,
                                left: 0,
                                width: '100%',
                                height: `40px`,
                                transform: `translateY(${virtualRow.start + HEADER_HEIGHT}px)`,
                            }}
                            className={clsx(
                                "flex items-center text-sm border-b border-neutral-100 dark:border-neutral-800 transition-colors",
                                // Row-Level Highlighting Priority
                                rowState === 'DUPLICATE'
                                    ? "bg-blue-50 dark:bg-blue-900/20 hover:bg-blue-100 dark:hover:bg-blue-900/30"
                                    : rowState === 'MULTIPLE'
                                        ? "bg-purple-50 dark:bg-purple-900/20 hover:bg-purple-100 dark:hover:bg-purple-900/30"
                                        : virtualRow.index % 2 === 0
                                            ? "bg-white dark:bg-neutral-900/50 hover:bg-neutral-50 dark:hover:bg-neutral-800/50"
                                            : "bg-neutral-50/50 dark:bg-neutral-900 hover:bg-neutral-100 dark:hover:bg-neutral-800"
                            )}
                        >
                            {columns.map((col) => {
                                const val = row[col];
                                const isMissing = val?.toString().toUpperCase() === '[MISSING]';
                                const issueType = rowIssues ? rowIssues[col] : null;
                                const width = getColumnWidth(col);

                                return (
                                    <div
                                        key={`${virtualRow.index}-${col}`}
                                        style={{ width }}
                                        className={clsx(
                                            "shrink-0 px-3 truncate border-r border-neutral-100 dark:border-neutral-800/50 last:border-r-0 h-full flex items-center transition-colors",
                                            // Interactive Cursor
                                            onCellClick && "cursor-[cell]",
                                            // Apply Highlight Class
                                            issueType === 'MISSING' && "bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 ring-inset ring-1 ring-red-200 dark:ring-red-800",
                                            issueType === 'FORMAT' && "bg-yellow-50 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-300 ring-inset ring-1 ring-yellow-200 dark:ring-yellow-800",
                                            issueType === 'DUPLICATE' && "bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 ring-inset ring-1 ring-blue-200 dark:ring-blue-800"
                                        )}
                                        onClick={() => onCellClick?.(virtualRow.index, col, val)}
                                    >
                                        {isMissing ? (
                                            <span className="text-inherit opacity-75 italic text-xs">
                                                Missing
                                            </span>
                                        ) : (
                                            <span className="text-neutral-700 dark:text-neutral-300">{val}</span>
                                        )}
                                    </div>
                                );
                            })}

                            {/* Action Column */}
                            {onDeleteRow && (
                                <div className="w-12 shrink-0 h-full flex items-center justify-center border-l border-neutral-100 dark:border-neutral-800 sticky right-0 bg-inherit transition-all">
                                    <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            onDeleteRow(virtualRow.index);
                                        }}
                                        className="p-1.5 rounded-md hover:bg-red-100 text-neutral-400 hover:text-red-600 transition-colors"
                                        title="Delete Row"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
});
DataGrid.displayName = 'DataGrid';
